-- Schema for Domain: crop | Business: Agriculture | Version: v1_ecm
-- Generated on: 2026-05-01 16:23:36

-- ========= DATABASE =========
CREATE DATABASE IF NOT EXISTS `agriculture_ecm`.`crop` COMMENT 'Core operational domain governing the full crop production lifecycle — from crop planning, seed selection, and planting schedules through cultivation, IPM-based pest and disease management, irrigation (ET-driven), VRA prescriptions, and NDVI-monitored field health. Manages field-level agronomic data, crop varieties, yield metrics (YPM, BU/acre), PHI and REI compliance, and FMIS integration with systems such as Climate FieldView, Trimble Ag Software, and SAP S/4HANA PP. Serves as the SSOT for all agronomic activity aligned with GAP standards.';

-- ========= TABLES =========
CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`growing_season` (
    `growing_season_id` BIGINT COMMENT 'Unique system-generated identifier for each growing season record. Serves as the primary key for the growing_season data product and is referenced by all crop production activity records (planting, cultivation, harvest, loss events) as the temporal anchor.',
    `climate_risk_indicator_id` BIGINT COMMENT 'Foreign key linking to weather.climate_risk_indicator. Business justification: Growing season planning incorporates climate risk assessments (drought, frost, heat stress) for enterprise budgeting, crop insurance decisions, and WASDE outlook alignment. Linking growing_season to c',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: The growing season defines which commodity is being produced — driving enterprise budgeting, crop insurance policy selection, and USDA ARC/PLC program enrollment. commodity_id normalizes the denormali',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Contract farming: a growing season is planned and executed for a specific buyer account (food manufacturer, grain elevator) under a forward supply contract. Links season-level organic, GMO, and variet',
    `double_crop_parent_season_id` BIGINT COMMENT 'For double-crop seasons, references the parent (primary) growing season that precedes this season on the same land area. Enables sequential crop tracking for double-crop rotations common in southern US (e.g., winter wheat followed by soybean). Null for primary or single-crop seasons.',
    `employee_id` BIGINT COMMENT 'Reference to the agronomist or crop advisor responsible for managing agronomic decisions during this growing season. Links to the workforce record in SAP SuccessFactors. Used for accountability tracking, GAP audit documentation, and FMIS user assignment in Climate FieldView and Trimble Ag Software.',
    `budget_id` BIGINT COMMENT 'Reference to the financial crop enterprise budget associated with this growing season in Granular Farm Management or SAP S/4HANA CO (Controlling). Links agronomic season records to CAPEX/OPEX planning, COGS (Cost of Goods Sold) tracking, and ROI (Return on Investment) analysis at the season level.',
    `farm_unit_id` BIGINT COMMENT 'Reference to the primary farm or agricultural operation entity under which this growing season is conducted. Links to the farm master record in Granular Farm Management and USDA FSA farm registration. Supports multi-farm enterprise reporting and land management hierarchy.',
    `organic_certification_id` BIGINT COMMENT 'Foreign key linking to product.organic_certification. Business justification: Organic growing seasons must be traceable to the specific NOP organic certification record for USDA NOP compliance audits, organic premium pricing, and annual renewal tracking. organic_certification_i',
    `quality_audit_id` BIGINT COMMENT 'Foreign key linking to quality.audit. Business justification: GAP and GlobalG.A.P. audits are scoped to a specific growing season. Certification management and audit scheduling require linking each season to its audit record. growing_season.gap_certification_sta',
    `quality_certification_id` BIGINT COMMENT 'Foreign key linking to quality.quality_certification. Business justification: Organic and GAP certifications are issued per season. growing_season.organic_certificate_number is a denormalized reference to the quality_certification record. Normalizing this FK supports certificat',
    `zone_id` BIGINT COMMENT 'Foreign key linking to weather.weather_zone. Business justification: Growing seasons are planned within climate/weather zones determining GDD targets, frost-free days, and irrigation requirements. climate_zone_code is a denormalized text reference to weather_zone. Prop',
    `actual_end_date` DATE COMMENT 'The actual date on which the growing season was formally closed, representing completion of the final harvest event and post-harvest handling. Captured from Climate FieldView harvest data or SAP S/4HANA PP production order closure. Used for season-over-season performance benchmarking.',
    `actual_start_date` DATE COMMENT 'The actual date on which field operations for the growing season commenced (first planting event recorded). Captured from John Deere Operations Center telematics or Climate FieldView planting data. Used to measure planting timeliness against planned window and assess weather-related delays.',
    `actual_yield_bu_acre` DECIMAL(18,2) COMMENT 'Realized yield for this growing season expressed in BU (Bushels) per acre, captured from harvest data in Climate FieldView or John Deere Operations Center yield monitors. Compared against target_yield_bu_acre for performance analysis. Used in USDA NASS yield surveys, crop insurance settlement, and FMIS season benchmarking.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this growing season record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Establishes the audit trail for record provenance in the Databricks Silver Layer lakehouse. Supports SOX (Sarbanes-Oxley Act) financial reporting controls and GDPR data lineage requirements.',
    `crop_insurance_coverage_type` STRING COMMENT 'Type of USDA RMA crop insurance or farm program coverage elected for this growing season. APH = Actual Production History, RP = Revenue Protection, RP_HPE = Revenue Protection with Harvest Price Exclusion, YP = Yield Protection, ARC = Agriculture Risk Coverage, PLC = Price Loss Coverage. Determines indemnity calculation methodology and premium rates.. Valid values are `APH|RP|RP_HPE|YP|ARC|PLC`',
    `crop_year` STRING COMMENT 'The marketing or production year associated with this growing season, expressed as a four-digit calendar year (e.g., 2024). Used for WASDE (World Agricultural Supply and Demand Estimates) alignment, USDA FSA program reporting, and financial crop enterprise budget year-over-year comparisons.',
    `fsma_compliance_flag` BOOLEAN COMMENT 'Indicates whether this growing seasons production activities are documented and compliant with FSMA (Food Safety Modernization Act) Produce Safety Rule requirements, including water testing, worker hygiene, and equipment sanitation records. Mandatory for covered produce operations under FDA jurisdiction.',
    `gap_certification_status` STRING COMMENT 'Current GAP (Good Agricultural Practices) certification status for this growing season. Indicates whether the production practices meet USDA GAP audit standards, GLOBALG.A.P. certification requirements, or buyer-mandated food safety standards (SQF, BRC, IFS). Required for retail and food manufacturer customer contracts.. Valid values are `certified|pending|not_applicable|expired`',
    `gdd_target` DECIMAL(18,2) COMMENT 'Target cumulative GDD (Growing Degree Days) required for the primary crop variety to reach maturity during this growing season. Used to project harvest timing, align PHI (Pre-Harvest Interval) compliance windows, and calibrate ET (Evapotranspiration)-based irrigation scheduling. Sourced from seed company variety data and NOAA climate records.',
    `ipm_program_code` STRING COMMENT 'Reference code identifying the IPM (Integrated Pest Management) program or protocol applied during this growing season. Links to the crop protection plan governing pesticide applications, REI (Restricted Entry Interval) compliance, MRL (Maximum Residue Limit) monitoring, and EPA pesticide registration requirements. Aligns with Trimble Ag Software scouting protocols.',
    `irrigation_method` STRING COMMENT 'Primary irrigation system used during this growing season. Determines ET (Evapotranspiration)-based water scheduling approach, water use efficiency reporting, and compliance with state water rights regulations. rainfed indicates no supplemental irrigation. Integrated with IoT (Internet of Things) soil moisture sensors and FMIS irrigation scheduling modules.. Valid values are `drip|sprinkler|center_pivot|flood|furrow|rainfed`',
    `is_gmo` BOOLEAN COMMENT 'Indicates whether the target crop variety for this season is a GMO (Genetically Modified Organism). Critical for USDA APHIS (Animal and Plant Health Inspection Service) regulatory compliance, COOL (Country of Origin Labeling) requirements, export documentation, and customer segregation requirements for non-GMO supply chains.',
    `is_organic_certified` BOOLEAN COMMENT 'Indicates whether this growing season is conducted under USDA National Organic Program (NOP) certified organic production standards. Triggers organic-specific input restrictions, record-keeping requirements, and supply chain segregation protocols. Linked to organic certificate management in compliance systems.',
    `ndvi_baseline_score` DECIMAL(18,2) COMMENT 'NDVI (Normalized Difference Vegetation Index) baseline score established at the start of the growing season, ranging from -1.0 to 1.0. Derived from satellite or drone imagery processed through Esri ArcGIS or Climate FieldView. Used as the reference benchmark for in-season crop health monitoring, stress detection, and VRA (Variable Rate Application) prescription adjustments.',
    `notes` STRING COMMENT 'Free-text field for agronomic observations, management decisions, weather events, or operational notes relevant to this growing season. Captures qualitative context not represented in structured fields, such as drought stress events, pest outbreak narratives, or regulatory inspection outcomes. Supports FMIS audit trail documentation.',
    `phi_days` STRING COMMENT 'Minimum number of days required between the last pesticide application and harvest for this growing seasons primary crop, as mandated by EPA pesticide label requirements (PHI — Pre-Harvest Interval). Critical for food safety compliance, MRL (Maximum Residue Limit) adherence, and FSMA (Food Safety Modernization Act) produce safety rule compliance.',
    `planned_end_date` DATE COMMENT 'The agronomically planned end date for the growing season, representing the expected completion of harvest and post-harvest handling operations. Derived from expected days-to-maturity of the target crop variety and planned planting date. Used for financial crop enterprise budget planning in Granular Farm Management.',
    `planned_start_date` DATE COMMENT 'The agronomically planned start date for the growing season, typically aligned with the target planting window based on GDD (Growing Degree Days), soil temperature thresholds, and historical climate data. Used in Trimble Ag Software field planning and Climate FieldView planting analytics.',
    `planting_method` STRING COMMENT 'Tillage and planting system employed during this growing season. Drives equipment configuration in John Deere Operations Center, soil disturbance impact on OM (Organic Matter) and EC (Electrical Conductivity) measurements, and BMP (Best Management Practices) compliance reporting for USDA EQIP (Environmental Quality Incentives Program) conservation programs.. Valid values are `conventional|no_till|strip_till|minimum_till|direct_seeding|transplanting`',
    `rei_hours` STRING COMMENT 'Minimum number of hours workers must stay out of treated fields after pesticide application during this growing season, as mandated by EPA Worker Protection Standard (REI — Restricted Entry Interval). Drives workforce scheduling in SAP SuccessFactors and OSHA compliance documentation for field worker safety.',
    `season_code` STRING COMMENT 'Externally-known alphanumeric business identifier for the growing season, used across FMIS systems such as Climate FieldView and Granular Farm Management for cross-system reference. Example: SPRING-2024-CORN, FALL-2024-SOY. Aligns with SAP S/4HANA PP production order season coding conventions.. Valid values are `^[A-Z0-9_-]{3,30}$`',
    `season_name` STRING COMMENT 'Human-readable descriptive name for the growing season, combining season type, year, and primary crop for operational clarity. Example: Spring 2024 Corn, Fall 2024 Soybean, Double-Crop 2024 Winter Wheat. Used in reporting dashboards and FMIS displays.',
    `season_status` STRING COMMENT 'Current lifecycle state of the growing season. planned indicates agronomic planning is underway but field operations have not commenced. active indicates planting through harvest operations are in progress. completed indicates harvest and post-harvest handling are finalized. cancelled indicates the season was abandoned (e.g., due to extreme weather or market conditions). suspended indicates temporary halt due to regulatory or operational constraints.. Valid values are `planned|active|completed|cancelled|suspended`',
    `season_type` STRING COMMENT 'Classification of the growing season by its agronomic timing and production strategy. double_crop supports sequential planting common in southern US and tropical operations. cover_crop denotes non-cash-crop seasons for soil health management per BMP (Best Management Practices). Drives planting window scheduling and FMIS season templates.. Valid values are `spring|fall|winter|summer|double_crop|cover_crop`',
    `target_crop_variety` STRING COMMENT 'Specific variety or hybrid designation of the primary crop planned for this season (e.g., DKC62-08RIB, AG36X6). Drives seed procurement, VRA (Variable Rate Application) prescriptions, and yield benchmarking by variety. Aligns with seed catalog codes in SAP S/4HANA MM and Trimble Ag Software variety trials.',
    `target_yield_bu_acre` DECIMAL(18,2) COMMENT 'Agronomically planned yield target for this growing season expressed in BU (Bushels) per acre, representing the YPM (Yield Per Acre Metric) goal. Established during crop planning based on historical yield data, soil productivity ratings, and variety performance benchmarks. Used as the baseline for financial crop enterprise budgets and crop insurance APH (Actual Production History).',
    `total_actual_area_acres` DECIMAL(18,2) COMMENT 'Total land area actually planted during this growing season, expressed in acres. May differ from planned area due to weather delays, equipment failures, or agronomic decisions. Captured from John Deere Operations Center planting telematics and Climate FieldView as-planted maps. Used for yield calculation (YPM) and insurance reporting.',
    `total_planned_area_acres` DECIMAL(18,2) COMMENT 'Total land area planned for production under this growing season, expressed in acres. Aggregated from associated field zone assignments. Used for input planning (seed, fertilizer, crop protection), equipment scheduling, and financial crop enterprise budget calculations in Granular Farm Management. Aligns with FSA farm records.',
    `total_yield_mt` DECIMAL(18,2) COMMENT 'Total harvested production volume for the growing season expressed in MT (Metric Tons), converted from bushel-based yield for international trade, export documentation, and supply chain logistics. Used in BOL (Bill of Lading) preparation, CIF/FOB export contracts, and WASDE supply estimates.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this growing season record, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Used for change data capture (CDC) in the Databricks lakehouse pipeline, optimistic concurrency control, and audit trail maintenance per SOX and GLOBALG.A.P. record-keeping requirements.',
    CONSTRAINT pk_growing_season PRIMARY KEY(`growing_season_id`)
) COMMENT 'Defines each agricultural growing season (e.g., Spring 2024 Corn, Fall 2024 Soybean) including season type (spring, fall, double-crop, cover crop), start and end dates, target crop, associated field zones, and season status (planned, active, completed). Acts as the temporal anchor for all crop production activities — planting, cultivation, harvest, and loss events — and links agronomic plans to financial crop enterprise budgets. Supports multi-crop and double-crop scenarios common in southern US and tropical operations. Aligns with FMIS season management in Climate FieldView and Granular.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`field_crop_plan` (
    `field_crop_plan_id` BIGINT COMMENT 'Unique surrogate identifier for the field crop plan record. Primary key for this entity in the Databricks Silver Layer lakehouse.',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Buyer-driven crop specifications: food manufacturers and retailers specify variety, organic certification, GMO status, and GlobalG.A.P. requirements at the field plan level. Linking field_crop_plan to',
    `cost_center_id` BIGINT COMMENT 'Foreign key linking to finance.cost_center. Business justification: Field crop plans are assigned to cost centers for management accounting and direct cost allocation by crop/field. Farm controllers require this link to allocate seed, fertilizer, and labor costs to th',
    `crop_enterprise_budget_id` BIGINT COMMENT 'Foreign key linking to finance.crop_enterprise_budget. Business justification: Field crop plans are the operational execution of enterprise budgets. Farm managers link plans to budgets for planned-vs-actual cost tracking and agronomic budget variance reporting — a core farm mana',
    `demand_forecast_id` BIGINT COMMENT 'Foreign key linking to sales.demand_forecast. Business justification: S&OP production planning: field crop plans are created in response to sales demand forecasts. Linking enables the S&OP process where agronomists confirm production plans against sales forecasts — a st',
    `employee_id` BIGINT COMMENT 'Reference to the certified agronomist responsible for authoring, approving, and overseeing execution of this crop plan. Required for GLOBALG.A.P. and GAP compliance documentation.',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field for which this crop plan is authored. Links to the field master record containing GIS boundaries, soil classification, and land tenure data.',
    `food_safety_plan_id` BIGINT COMMENT 'Foreign key linking to compliance.food_safety_plan. Business justification: FSMA Produce Safety Rule requires field-level growing activities to operate under an approved food safety plan. Linking field_crop_plan to food_safety_plan enables FSMA compliance verification, ensuri',
    `growing_season_id` BIGINT COMMENT 'Reference to the growing season (crop year) for which this plan applies. Aligns with USDA crop year definitions and SAP S/4HANA PP planning horizon.',
    `haccp_plan_id` BIGINT COMMENT 'Foreign key linking to quality.haccp_plan. Business justification: Food-grade crop plans must reference the governing HACCP plan for the commodity. FSMA Preventive Controls requires that agronomic plans align with food safety hazard controls. A domain expert would ex',
    `land_soil_sample_id` BIGINT COMMENT 'Foreign key linking to land.soil_sample. Business justification: Field crop plans are built from specific soil test reports; soil_ph_baseline, soil_om_pct, and soil_cec on field_crop_plan are denormalized from soil_sample. Linking to soil_sample enables traceabilit',
    `planting_window_id` BIGINT COMMENT 'Foreign key linking to weather.planting_window. Business justification: Field crop plans set planned_planting_date based on the approved planting window for the field/season. Linking field_crop_plan to planting_window supports agronomic plan traceability, insurance docume',
    `contract_id` BIGINT COMMENT 'Foreign key linking to sales.contract. Business justification: Contract farming production planning: field crop plans are often created specifically to fulfill a forward sales contract. Linking enables contract farming management where production plans are tied t',
    `seed_variety_id` BIGINT COMMENT 'Reference to the specific crop variety (cultivar) selected for this field and season, including GMO status, maturity rating, and trait profile. Links to the crop variety master in the seed catalog.',
    `vra_prescription_id` BIGINT COMMENT 'Reference to the VRA (Variable Rate Application) prescription file generated in Trimble Ag Software or Climate FieldView for this crop plan. Enables site-specific input application based on NDVI and soil variability zones.',
    `approved_date` DATE COMMENT 'Date on which the responsible agronomist formally approved this crop plan for execution. Required for GLOBALG.A.P. and GAP compliance audit documentation.',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp recording when this field crop plan record was first created in the lakehouse Silver Layer. Supports data lineage, audit trail, and FSMA record-keeping requirements.',
    `globalg_ap_certified` BOOLEAN COMMENT 'Indicates whether this field crop plan is authored and executed under an active GLOBALG.A.P. (Global Good Agricultural Practices) certification scope. Drives audit documentation requirements and customer supply chain eligibility.',
    `gmo_trait_used` BOOLEAN COMMENT 'Indicates whether the selected crop variety contains one or more GMO (Genetically Modified Organism) traits. Required for USDA APHIS biotech regulatory compliance, COOL (Country of Origin Labeling), and export documentation to GMO-restricted markets.',
    `irrigation_system_type` STRING COMMENT 'Type of irrigation infrastructure deployed on this field. Determines ET (Evapotranspiration)-based scheduling methodology, water application efficiency, and water allocation compliance reporting.. Valid values are `drip|center_pivot|flood|sprinkler|subsurface_drip|none`',
    `irrigation_target_depth_inches` DECIMAL(18,2) COMMENT 'Planned total irrigation water application depth in acre-inches for the season, derived from ET-deficit modeling and soil moisture trigger thresholds. Supports water allocation compliance and USDA NRCS irrigation water management standards.',
    `ndvi_baseline` DECIMAL(18,2) COMMENT 'Pre-season NDVI (Normalized Difference Vegetation Index) baseline value for the field, ranging from -1.0 to 1.0. Used to establish field health benchmarks for in-season monitoring and VRA prescription calibration. Sourced from Esri ArcGIS or Climate FieldView satellite imagery.',
    `nutrient_setback_zone_ft` DECIMAL(18,2) COMMENT 'Minimum buffer distance in feet from water bodies, drainage ditches, and sensitive areas within which nutrient applications are restricted or prohibited. Defined per EPA nutrient management regulations and state BMP requirements. Captured in Esri ArcGIS environmental layer.',
    `organic_certified` BOOLEAN COMMENT 'Indicates whether this crop plan is executed under USDA National Organic Program (NOP) certification, restricting inputs to approved organic materials and requiring organic system plan documentation.',
    `phi_days` STRING COMMENT 'Minimum number of days that must elapse between the last pesticide application and harvest, as mandated by EPA pesticide label requirements. Critical for MRL (Maximum Residue Limit) compliance and food safety certification under FSMA and GLOBALG.A.P.',
    `plan_date` DATE COMMENT 'The business date on which this crop plan was formally created and entered into the Farm Management Information System (FMIS). Distinct from system audit timestamps.',
    `plan_number` STRING COMMENT 'Externally-known business identifier for the crop plan, used in Trimble Ag Software, Climate FieldView, and SAP S/4HANA PP module for cross-system reference and traceability. Format: FCP-{YEAR}-{ALPHANUMERIC}.. Valid values are `^FCP-[0-9]{4}-[A-Z0-9]{6,12}$`',
    `plan_status` STRING COMMENT 'Current lifecycle state of the field crop plan. Draft: under preparation; Approved: signed off by agronomist; Active: in-season execution underway; Completed: season closed; Cancelled: plan voided; Superseded: replaced by a revised plan version.. Valid values are `draft|approved|active|completed|cancelled|superseded`',
    `plan_version` STRING COMMENT 'Monotonically incrementing version number for the crop plan. Incremented each time the plan is revised and re-approved, supporting audit trail and change management requirements under FSMA and GLOBALG.A.P.',
    `planned_area_acres` DECIMAL(18,2) COMMENT 'Total field area in acres designated for crop production under this plan. Used for input quantity calculations, yield projections, and USDA FSA acreage reporting. Sourced from Esri ArcGIS field boundary data.',
    `planned_harvest_date` DATE COMMENT 'Target calendar date for harvest operations to commence on this field. Drives downstream supply chain scheduling, storage capacity planning, and logistics coordination via SAP S/4HANA SD and TMS.',
    `planned_planting_date` DATE COMMENT 'Target calendar date for planting operations to commence on this field, as defined in the crop plan. Used for scheduling labor, equipment, and input procurement in SAP S/4HANA PP and Trimble Ag Software.',
    `rei_hours` STRING COMMENT 'Minimum number of hours workers must stay out of treated fields after pesticide application, as specified on EPA-registered pesticide labels. Required for OSHA worker protection standard compliance and GLOBALG.A.P. worker safety documentation.',
    `row_spacing_inches` DECIMAL(18,2) COMMENT 'Planned distance between crop rows in inches, as specified in the planting prescription. Affects canopy closure, weed suppression, and machinery configuration. Integrated with Trimble Ag Software VRA prescriptions.',
    `soil_test_date` DATE COMMENT 'Date on which soil samples were collected for the baseline soil test underpinning this crop plans nutrient management recommendations. Required for GLOBALG.A.P. and EPA nutrient management compliance documentation.',
    `target_k_rate_lbs_acre` DECIMAL(18,2) COMMENT 'Planned potassium (K) fertilizer application rate in pounds per acre, based on soil test K levels and crop removal rates. Part of the NPK nutrient management plan. Influences crop quality, disease resistance, and water use efficiency.',
    `target_n_rate_lbs_acre` DECIMAL(18,2) COMMENT 'Planned nitrogen (N) fertilizer application rate in pounds per acre, derived from soil test results and yield goal. Core component of the NPK (Nitrogen Phosphorus Potassium) nutrient management plan. Must comply with EPA nutrient management regulations and state BMP requirements.',
    `target_p_rate_lbs_acre` DECIMAL(18,2) COMMENT 'Planned phosphorus (P) fertilizer application rate in pounds per acre, based on soil test P levels and crop removal rates. Part of the NPK nutrient management plan. Subject to EPA and state environmental setback zone restrictions.',
    `target_plant_population` STRING COMMENT 'Planned seeding rate expressed as seeds per acre. Drives seed quantity procurement, VRA prescription generation, and yield modeling. Sourced from Trimble Ag Software and Climate FieldView planting prescriptions.',
    `tillage_method` STRING COMMENT 'Planned soil tillage approach for land preparation prior to planting. Influences soil health, erosion risk, fuel consumption, and BMP compliance. Captured in Trimble Ag Software field planning module.. Valid values are `conventional|reduced_till|no_till|strip_till|deep_rip`',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp recording when this field crop plan record was most recently modified. Supports change management, version control, and audit trail requirements under FSMA and GLOBALG.A.P.',
    `water_allocation_limit_acre_ft` DECIMAL(18,2) COMMENT 'Maximum permitted water volume in acre-feet that may be applied to this field during the season, as defined by water rights permits or irrigation district allocations. Enforced for regulatory compliance with state water authorities.',
    `yield_target_bu_acre` DECIMAL(18,2) COMMENT 'Expected crop yield expressed in BU (Bushels) per acre for the planned field and season. Serves as the primary agronomic performance benchmark for YPM (Yield Per Acre Metric) reporting and WASDE comparison. Null if crop is measured in MT or CWT.',
    `yield_target_mt_hectare` DECIMAL(18,2) COMMENT 'Expected crop yield expressed in MT (Metric Tons) per hectare, used for international reporting and crops not measured in bushels. Complements BU/acre target for global supply chain and export documentation.',
    CONSTRAINT pk_field_crop_plan PRIMARY KEY(`field_crop_plan_id`)
) COMMENT 'Comprehensive agronomic plan for a specific field and growing season, serving as the single operational blueprint for all planned crop activities. Consolidates all sub-planning disciplines into one authoritative document. Captures: (1) Crop selection — intended crop variety, target planting population (seeds/acre), row spacing, tillage method. (2) Nutrient management — target NPK removal rates, soil test baseline (pH, NPK, CEC, OM), recommended fertilizer products and rates, application timing windows, environmental setback zones, EPA nutrient management compliance. (3) Irrigation strategy — ET-deficit and soil moisture trigger thresholds, target application depth (acre-inches), water allocation limits, irrigation system type. (4) IPM program — target pests and diseases, economic threshold levels, monitoring frequency, preferred intervention hierarchy (biological, cultural, chemical), approved agrochemicals, responsible agronomist. (5) Yield target — expected yield (BU/acre or YPM), benchmark comparisons. Integrates with Trimble Ag Software and Climate FieldView for VRA prescription generation. Supports EPA nutrient management compliance, BMP documentation, GLOBALG.A.P. crop protection standards, and IPM guidelines.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`planting_event` (
    `planting_event_id` BIGINT COMMENT 'Unique surrogate identifier for each planting event record in the Silver layer lakehouse. Primary key for the planting_event data product.',
    `asset_id` BIGINT COMMENT 'Reference to the planting equipment (planter, seeder) used during this event, sourced from John Deere Operations Center fleet telematics records.',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: Seed planting consumes a specific inventory commodity lot. Linking planting_event to commodity_lot enables FSMA seed traceability and inventory depletion reconciliation — a domain expert expects to tr',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Planting crew tracking: large-scale planting operations are crew-based. Linking planting_event to crew supports piece-rate payroll for planting crews, H2A labor compliance verification, and labor cost',
    `employee_id` BIGINT COMMENT 'Reference to the equipment operator or farm worker who executed the planting operation. Supports workforce accountability and GAP traceability.',
    `equipment_field_operation_id` BIGINT COMMENT 'Foreign key linking to equipment.field_operation. Business justification: Planting events are the agronomic record; field_operation is the equipment execution record. Linking enables reconciliation of prescribed vs. actual seeding rates, area coverage accuracy, and planter ',
    `field_crop_plan_id` BIGINT COMMENT 'Reference to the agronomic crop plan that authorized and scheduled this planting event, linking actual execution back to the planned prescription.',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field on which this planting event was executed. Links to the field master record containing boundary, acreage, and soil zone data.',
    `forecast_id` BIGINT COMMENT 'Foreign key linking to weather.forecast. Business justification: Planting decisions are authorized based on weather forecasts (frost risk, soil temperature outlook). Linking planting_event to the forecast used supports agronomic decision audit trails and crop insur',
    `goods_issue_id` BIGINT COMMENT 'Foreign key linking to inventory.goods_issue. Business justification: Seed planting consumes seed inventory recorded as a goods issue. Linking planting_event to goods_issue enables seed consumption reconciliation — confirming seed goods issued from inventory matches act',
    `growing_season_id` BIGINT COMMENT 'Foreign key linking to crop.growing_season. Business justification: planting_event currently stores crop_season (STRING) and crop_year (INT) as denormalized text/integer representations of the growing season. Adding season_id as a proper FK to growing_season.growing_s',
    `planting_window_id` BIGINT COMMENT 'Foreign key linking to weather.planting_window. Business justification: Planting events are executed within approved planting windows (soil temperature, trafficability, frost risk). Linking the actual planting event to the authorizing planting window is a core agronomic s',
    `seed_lot_id` BIGINT COMMENT 'Reference to the seed lot (LOT) used in this planting event, enabling full traceability from seed supplier through planting to harvest per GAP and FSMA requirements.',
    `seed_variety_id` BIGINT COMMENT 'Reference to the specific crop variety or hybrid planted during this event, linking to the crop variety master for species, hybrid code, and trait information.',
    `soil_profile_id` BIGINT COMMENT 'Foreign key linking to land.soil_profile. Business justification: Planting decisions (depth, seeding rate, row spacing) are operationally driven by soil profile data (texture, drainage class, depth-to-restrictive-layer). Agronomists reference the soil profile when e',
    `air_temperature_c` DECIMAL(18,2) COMMENT 'Ambient air temperature at the time of planting, expressed in degrees Celsius. Used alongside soil temperature for planting condition assessment and growing degree day (GDD) baseline calculations.',
    `area_planted_acres` DECIMAL(18,2) COMMENT 'Total field area covered by this planting event, measured in acres as GPS-tracked by John Deere Operations Center. Used for seed usage reconciliation, cost allocation, and yield per acre (YPM) calculations.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this planting event record was first created in the system, representing the audit trail creation point for data governance and lineage tracking.',
    `event_number` STRING COMMENT 'Externally-visible business identifier for this planting event, formatted as PLT-{YEAR}-{SEQUENCE}. Used in field records, GAP audit documentation, and FMIS reporting.. Valid values are `^PLT-[0-9]{4}-[0-9]{6}$`',
    `event_status` STRING COMMENT 'Current lifecycle status of the planting event. planned = scheduled but not started; in_progress = actively being executed; completed = fully finished; cancelled = aborted before execution; partial = field partially planted due to weather or equipment stoppage.. Valid values are `planned|in_progress|completed|cancelled|partial`',
    `gap_compliant` BOOLEAN COMMENT 'Indicates whether this planting event was executed in full compliance with Good Agricultural Practices (GAP) standards, including seed traceability, equipment calibration records, and operator certification. Required for GLOBALG.A.P. and GFSI audit readiness.',
    `gps_coverage_geojson` STRING COMMENT 'GeoJSON string representing the GPS-tracked boundary and coverage path of the planting operation, sourced from John Deere Operations Center or Trimble RTK guidance system. Enables as-planted map generation in Esri ArcGIS and Climate FieldView.',
    `hybrid_code` STRING COMMENT 'Seed companys commercial hybrid or variety code as labeled on the seed bag (e.g., DKC62-08RIB). Distinct from the internal crop_variety_id — this is the supplier-assigned commercial identifier used for agronomic benchmarking and seed procurement.',
    `is_gmo` BOOLEAN COMMENT 'Indicates whether the planted seed variety is a Genetically Modified Organism (GMO). Required for USDA APHIS regulatory compliance, COOL labeling, and customer supply chain transparency disclosures.',
    `is_organic_certified` BOOLEAN COMMENT 'Indicates whether the seed used in this planting event is certified organic under the USDA National Organic Program (NOP). Required for organic certification audit trails and premium market channel eligibility.',
    `notes` STRING COMMENT 'Free-text field for agronomist or operator observations recorded at the time of planting, such as equipment issues, field condition anomalies, or deviations from the prescription. Supports GAP audit documentation and agronomic decision records.',
    `phi_days` STRING COMMENT 'Pre-Harvest Interval (PHI) in days applicable to any seed treatments applied, representing the minimum number of days that must elapse between planting/treatment and harvest. Critical for MRL compliance and food safety. Sourced from EPA pesticide label.',
    `planting_date` DATE COMMENT 'Calendar date on which the planting operation was executed. Critical for PHI (Pre-Harvest Interval) calculation, growing degree day (GDD) accumulation, and crop insurance compliance.',
    `planting_depth_cm` DECIMAL(18,2) COMMENT 'Actual seed placement depth below soil surface in centimeters, as recorded by the planter monitor. Critical for germination uniformity and stand establishment. Sourced from John Deere Operations Center.',
    `planting_end_timestamp` TIMESTAMP COMMENT 'Precise date and time when the planting operation was completed or stopped, sourced from John Deere Operations Center machine telemetry. Used with start timestamp to compute field operation duration.',
    `planting_method` STRING COMMENT 'Tillage and planting method used for this event. Supports soil health tracking, carbon sequestration reporting, and BMP compliance. [ENUM-REF-CANDIDATE: conventional|no_till|strip_till|minimum_till|direct_seeding|transplanting — promote to reference product if additional methods are needed]. Valid values are `conventional|no_till|strip_till|minimum_till|direct_seeding|transplanting`',
    `planting_start_timestamp` TIMESTAMP COMMENT 'Precise date and time when the planting operation commenced, sourced from John Deere Operations Center machine telemetry. Used for operational duration analysis and OEE calculations.',
    `rei_hours` DECIMAL(18,2) COMMENT 'Restricted Entry Interval (REI) in hours for any seed treatments applied, specifying the minimum time workers must stay out of treated areas after planting. Required for OSHA and EPA worker protection standard compliance.',
    `row_spacing_cm` DECIMAL(18,2) COMMENT 'Actual row spacing achieved during planting, measured in centimeters. Affects canopy closure, weed suppression, and yield potential. Sourced from planter configuration data in John Deere Operations Center.',
    `seed_treatment` STRING COMMENT 'Description of any chemical or biological seed treatments applied prior to planting (e.g., fungicide, insecticide, inoculant). Required for PHI/REI compliance tracking and EPA pesticide use reporting. Sourced from seed bag label or agronomist records.',
    `seeding_rate_actual` DECIMAL(18,2) COMMENT 'Actual average seeding rate achieved during the planting operation, expressed in seeds per acre. Sourced from John Deere Operations Center planter monitor data. Compared against the prescribed VRA seeding rate for agronomic performance analysis.',
    `seeding_rate_prescribed` DECIMAL(18,2) COMMENT 'Target seeding rate specified in the VRA (Variable Rate Application) prescription for this field zone, expressed in seeds per acre. Sourced from Trimble Ag Software prescription maps.',
    `soil_moisture_pct` DECIMAL(18,2) COMMENT 'Volumetric soil moisture content at the time of planting, expressed as a percentage. Influences seed-to-soil contact quality and germination success. Sourced from soil moisture sensors or field scouting records.',
    `soil_temperature_c` DECIMAL(18,2) COMMENT 'Soil temperature at seed depth measured at the time of planting, expressed in degrees Celsius. Key agronomic indicator for germination risk assessment and planting timing decisions. Sourced from in-cab sensors or field weather stations.',
    `source_system` STRING COMMENT 'Originating operational system from which this planting event record was sourced. Supports data lineage, Silver layer reconciliation, and conflict resolution when multiple systems report the same event.. Valid values are `john_deere_ops_center|climate_fieldview|trimble_ag|granular|manual_entry`',
    `source_system_event_reference` STRING COMMENT 'Native identifier of this planting event in the originating source system (e.g., John Deere Operations Center task ID or Climate FieldView activity ID). Enables reverse lookup and reconciliation with the system of record.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this planting event record. Supports Silver layer incremental processing and audit trail requirements.',
    `weather_condition` STRING COMMENT 'Observed weather condition at the time of planting. Supports agronomic analysis of planting conditions versus stand establishment outcomes and crop insurance documentation. [ENUM-REF-CANDIDATE: clear|partly_cloudy|overcast|light_rain|heavy_rain|windy|foggy — promote to reference product if additional conditions are needed]',
    CONSTRAINT pk_planting_event PRIMARY KEY(`planting_event_id`)
) COMMENT 'Transactional record of an actual planting operation executed on a field, capturing planting date, operator, equipment used, seed lot number (LOT), actual seeding rate (seeds/acre), row spacing achieved, planting depth, soil temperature at planting, and GPS-tracked field coverage. Sourced from John Deere Operations Center and Climate FieldView planting data. Supports GAP traceability and PHI/REI compliance tracking.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`seed_lot` (
    `seed_lot_id` BIGINT COMMENT 'Unique system-generated identifier for each seed lot master record. Primary key for the seed_lot data product. Role: MASTER_RESOURCE.',
    `certificate_of_analysis_id` BIGINT COMMENT 'Foreign key linking to quality.certificate_of_analysis. Business justification: Seed lots require COAs documenting germination rate, purity, seed treatment active ingredients, and organic certification. seed_lot.coa_number is a denormalized reference. Normalizing to FK supports s',
    `organic_certification_id` BIGINT COMMENT 'Foreign key linking to product.organic_certification. Business justification: NOP regulations require organic operations to use organically produced seed when commercially available. Linking seed_lot to organic_certification enables NOP compliance verification that certified or',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Seed lot traceability to the originating PO is required for GlobalG.A.P. and FSMA compliance. Replaces denormalized purchase_order_number plain text attribute with a proper FK enabling full procuremen',
    `seed_variety_id` BIGINT COMMENT 'Reference to the crop variety master record associated with this seed lot, linking the lot to its specific genetic variety, species, and crop type classification.',
    `storage_location_id` BIGINT COMMENT 'Reference to the physical storage location (warehouse bin, cold storage unit, or seed storage facility) where this seed lot is currently stored. Maps to SAP S/4HANA MM storage location (LGORT) and Manhattan Associates WMS location master.',
    `vendor_id` BIGINT COMMENT 'Reference to the seed supplier or vendor who provided this seed lot. Links to the supplier master for procurement traceability and vendor performance management. Maps to SAP S/4HANA MM vendor master (LFA1).',
    `certification_class` STRING COMMENT 'AOSCA-defined seed certification class indicating the generation and purity level of the seed lot. breeder = source seed from plant breeder; foundation = first generation from breeder seed; registered = second generation; certified = third generation approved for commercial use; uncertified = not certified.. Valid values are `breeder|foundation|registered|certified|uncertified`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this seed lot record was first created in the system, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports audit trail, data lineage, and FSMA record-keeping requirements.',
    `crop_species` STRING COMMENT 'Botanical or common species name of the crop seed in this lot (e.g., Zea mays for corn, Glycine max for soybean, Triticum aestivum for wheat). Used for regulatory reporting, crop rotation planning, and USDA compliance.',
    `currency_code` STRING COMMENT 'Three-letter ISO 4217 currency code for the unit_cost of this seed lot (e.g., USD, EUR, BRL). Required for multi-currency financial reporting under IFRS and GAAP, and for SAP S/4HANA FI currency management.. Valid values are `^[A-Z]{3}$`',
    `germination_expiry_date` DATE COMMENT 'Date after which the germination rate certification is no longer valid and retesting is required per USDA Federal Seed Act regulations. Drives lot status transitions to expired and triggers procurement or retesting workflows.',
    `germination_rate_pct` DECIMAL(18,2) COMMENT 'Percentage of seeds in this lot that germinated under standard test conditions, as reported on the seed tag or Certificate of Analysis (COA). Expressed as a percentage (0.00–100.00). Critical for seeding rate calculations, yield forecasting (YPM), and USDA Federal Seed Act minimum germination standards compliance.',
    `germination_test_date` DATE COMMENT 'Date on which the germination test was conducted for this seed lot, as reported on the seed tag or COA (Certificate of Analysis). Used to determine germination validity period and compliance with USDA Federal Seed Act labeling requirements.',
    `gmo_trait_stack` STRING COMMENT 'Identifier or description of the GMO (Genetically Modified Organism) trait stack present in this seed lot (e.g., RR2Y/YGCB, Roundup Ready 2 Yield + YieldGard Corn Borer). NULL if non-GMO. Required for USDA APHIS biotech regulatory compliance, COOL labeling, and customer GMO disclosure requirements.',
    `is_gmo` BOOLEAN COMMENT 'Indicates whether this seed lot contains genetically modified organisms (GMO). True = GMO seed; False = non-GMO seed. Required for USDA National Bioengineered Food Disclosure Standard compliance, customer labeling, and export documentation.',
    `is_organic_certified` BOOLEAN COMMENT 'Indicates whether this seed lot is certified under the USDA National Organic Program (NOP). True = NOP-certified organic seed; False = conventional seed. Required for organic crop production compliance and NOP audit trails.',
    `lot_number` STRING COMMENT 'Externally-known alphanumeric lot number (LOT) assigned by the seed supplier or internal seed processing facility. Used for seed traceability from procurement through planting to harvest, and for FSMA seed traceability compliance. Maps to SAP S/4HANA MM batch number (CHARG) and Granular Farm Management lot tracking.',
    `lot_status` STRING COMMENT 'Current lifecycle status of the seed lot. available = in storage and ready for use; reserved = allocated to a planting plan; planted = fully consumed in field operations; depleted = quantity exhausted; quarantined = held pending quality or regulatory review; expired = past germination validity date.. Valid values are `available|reserved|planted|depleted|quarantined|expired`',
    `moisture_content_pct` DECIMAL(18,2) COMMENT 'Moisture content of the seed lot expressed as a percentage at time of testing or receipt. Critical for safe storage, preventing mold and mycotoxin development, and maintaining germination viability. Monitored per USDA grain storage standards.',
    `noxious_weed_free` BOOLEAN COMMENT 'Indicates whether this seed lot has been certified as free of noxious weed seeds as defined by USDA Federal Seed Act and applicable state seed laws. True = certified noxious weed free; False = noxious weed seeds detected or certification not obtained. Required for interstate commerce compliance.',
    `purity_pct` DECIMAL(18,2) COMMENT 'Percentage of pure seed (by weight) in this lot as determined by seed analysis, excluding inert matter, other crop seed, and weed seed. Expressed as a percentage (0.00–100.00). Required for USDA Federal Seed Act labeling compliance and AOSCA certification standards.',
    `quantity_remaining` DECIMAL(18,2) COMMENT 'Current remaining quantity of seed in this lot available for planting, expressed in the unit_of_measure. Updated as seed is allocated to planting operations. Supports inventory planning, seeding rate calculations, and procurement replenishment decisions.',
    `quantity_units` DECIMAL(18,2) COMMENT 'Total quantity of seed in this lot expressed in the applicable unit of measure (seeds, bags, CWT, or BU as defined in unit_of_measure). Tracks available inventory for planting planning, procurement, and WMS (Warehouse Management System) inventory control in Manhattan Associates WMS.',
    `receipt_date` DATE COMMENT 'Date on which this seed lot was physically received at the storage facility. Marks the start of the lots custody chain for FSMA traceability, FIFO inventory management, and storage duration tracking.',
    `relative_maturity_days` STRING COMMENT 'Relative maturity rating of the crop variety in this seed lot, expressed in days or heat units (e.g., 95-day corn, 3.8 maturity group soybean). Critical for crop planning, harvest scheduling, and matching variety to growing season length in the FMIS.',
    `seed_origin_country` STRING COMMENT 'Three-letter ISO 3166-1 alpha-3 country code indicating the country where this seed lot was produced or conditioned. Required for USDA Country of Origin Labeling (COOL) compliance, import/export documentation, and APHIS phytosanitary certification.. Valid values are `^[A-Z]{3}$`',
    `seed_rate_per_acre` DECIMAL(18,2) COMMENT 'Supplier-recommended seeding rate for this seed lot expressed in seeds or units per acre. Used in VRA (Variable Rate Application) prescription generation in Trimble Ag Software and Climate FieldView, and for planting plan calculations in FMIS.',
    `seed_treatment_product` STRING COMMENT 'Commercial name of the seed treatment product applied to this lot (e.g., Cruiser Maxx, Poncho/VOTiVO, Apron XL). Required for EPA FIFRA compliance, SDS (Safety Data Sheet) reference, and agronomic record-keeping under GAP standards.',
    `seed_treatment_type` STRING COMMENT 'Type of chemical or biological coating applied to the seed lot prior to packaging. fungicide = fungicide-only coating; insecticide = insecticide-only coating; fungicide_insecticide = combined coating; biological = biological agent coating; untreated = no treatment applied. Required for EPA pesticide registration compliance, REI (Restricted Entry Interval) tracking, and PHI (Pre-Harvest Interval) management.. Valid values are `fungicide|insecticide|fungicide_insecticide|biological|untreated`',
    `test_weight_lbs_bu` DECIMAL(18,2) COMMENT 'Test weight of the seed lot expressed in pounds per bushel (BU), indicating seed density and quality. Used for quality grading, storage planning, and yield estimation. Aligns with USDA grain grading standards.',
    `thousand_seed_weight_g` DECIMAL(18,2) COMMENT 'Weight of 1,000 seeds in grams (TSW), used to calculate seeding rates by weight, estimate seed counts per bag, and assess seed size uniformity. Standard agronomic quality metric used in FMIS and precision planting systems.',
    `treatment_active_ingredient` STRING COMMENT 'Active Ingredient (AI) of the seed treatment applied to this lot (e.g., thiamethoxam, fludioxonil, metalaxyl). Required for EPA FIFRA compliance, MRL (Maximum Residue Limit) tracking, and food safety regulatory reporting.',
    `treatment_date` DATE COMMENT 'Date on which the seed treatment was applied to this lot. Used to calculate treatment age, validate treatment efficacy windows, and support EPA FIFRA compliance and PHI/REI tracking.',
    `unit_cost` DECIMAL(18,2) COMMENT 'Procurement cost per unit of measure for this seed lot (in USD), as recorded at time of purchase. Used for COGS (Cost of Goods Sold) calculation, crop enterprise budgeting, CAPEX/OPEX reporting, and financial planning in SAP S/4HANA CO and Granular Farm Management.',
    `unit_of_measure` STRING COMMENT 'Unit of measure for the seed lot quantity (e.g., seeds for precision count, bags for packaged units, CWT for hundredweight, BU for bushels, kg or lbs for weight-based). Aligns with SAP S/4HANA MM base unit of measure (MEINS) and USDA commodity reporting standards.. Valid values are `seeds|bags|CWT|BU|kg|lbs`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent update to this seed lot record, in ISO 8601 format (yyyy-MM-ddTHH:mm:ss.SSSXXX). Supports change tracking, data lineage, and audit compliance for FSMA and SOX requirements.',
    `vigor_score` DECIMAL(18,2) COMMENT 'Seed vigor test score indicating the potential for rapid, uniform emergence under field stress conditions, expressed as a percentage or index (0.00–100.00). Complements germination rate for predicting field performance. Tested per AOSA/ISTA vigor testing protocols.',
    `weed_seed_pct` DECIMAL(18,2) COMMENT 'Percentage of weed seed (by weight) found in this seed lot during purity analysis. Must meet USDA Federal Seed Act and state seed law maximum thresholds. High weed seed content may trigger quarantine or rejection.',
    CONSTRAINT pk_seed_lot PRIMARY KEY(`seed_lot_id`)
) COMMENT 'Master record for each seed lot (LOT) received and used in planting operations, including crop variety reference, supplier, lot number, germination rate, purity percentage, seed treatment details (fungicide/insecticide coating, treatment date), GMO trait stack, test weight, and storage location. Provides full seed traceability from procurement through planting to harvest. Supports FSMA seed traceability, USDA seed certification compliance, and AOSCA seed labeling requirements.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`fertilization_event` (
    `fertilization_event_id` BIGINT COMMENT 'Unique system-generated identifier for each fertilizer application event record. Serves as the primary key for the fertilization_event data product in the crop domain Silver layer.',
    `asset_id` BIGINT COMMENT 'Reference to the equipment or machinery used to perform the fertilizer application (e.g., spreader, sprayer, fertigation system). Links to the equipment master for maintenance and OEE tracking.',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: Fertilization events consume a specific fertilizer lot. Linking to commodity_lot enables lot-level nutrient management traceability, MRL compliance reporting, and inventory depletion — required for nu',
    `employee_id` BIGINT COMMENT 'Reference to the operator or equipment operator who performed the fertilizer application. Used for workforce accountability and GAP compliance traceability.',
    `equipment_field_operation_id` BIGINT COMMENT 'Foreign key linking to equipment.field_operation. Business justification: Fertilization events record agronomic application details; field_operation records equipment execution. Linking enables nutrient management plan compliance verification, application rate accuracy audi',
    `field_crop_plan_id` BIGINT COMMENT 'Foreign key linking to crop.field_crop_plan. Business justification: fertilization_event links to vra_prescription and growing_season but has no direct FK to field_crop_plan. The field crop plan defines target N/P/K rates (target_n_rate_lbs_acre, target_p_rate_lbs_acre',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field on which the fertilizer application event occurred. Links to the field master record containing boundary, acreage, and soil zone data.',
    `growing_season_id` BIGINT COMMENT 'Reference to the crop season or growing season during which this fertilization event occurred. Enables agronomic analysis by season and year.',
    `input_product_id` BIGINT COMMENT 'Reference to the fertilizer product or material applied during this event. Links to the product/material master containing NPK formulation, active ingredient, and regulatory details.',
    `land_soil_sample_id` BIGINT COMMENT 'Foreign key linking to land.soil_sample. Business justification: Nutrient management plans and state regulatory compliance require traceability from each fertilization event back to the soil test (COA) that justified the application rate. NRCS and state nutrient ma',
    `management_zone_id` BIGINT COMMENT 'Foreign key linking to land.management_zone. Business justification: VRA fertilization events are executed at management zone level. Precision agriculture systems track nutrient application by zone for zone-level ROI analysis and variable-rate compliance reporting. No ',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: Nutrient management audits and FSMA compliance require traceability from fertilizer application events back to the procurement PO and vendor. Replaces denormalized supplier_name. A domain expert expec',
    `spray_window_id` BIGINT COMMENT 'Foreign key linking to weather.spray_window. Business justification: Liquid and foliar fertilizer applications require compliant weather windows (wind, rain-free period, temperature) for BMP and nutrient management plan compliance. Linking fertilization_event to the au',
    `vra_prescription_id` BIGINT COMMENT 'Reference to the Variable Rate Application (VRA) prescription that authorized or guided this fertilization event. Null if the application was performed without a prescription (flat-rate application).',
    `actual_rate` DECIMAL(18,2) COMMENT 'The actual fertilizer application rate recorded during the field operation, expressed in the unit defined by rate_unit. Sourced from John Deere Operations Center or Trimble Ag as-applied data. Compared against planned_rate for VRA compliance and agronomic audit.',
    `application_date` DATE COMMENT 'The calendar date on which the fertilizer was applied to the field. This is the principal real-world business event date used for agronomic scheduling, PHI/REI compliance tracking, and nutrient management reporting.',
    `application_end_timestamp` TIMESTAMP COMMENT 'Precise date and time when the fertilizer application operation was completed in the field. Used to calculate application duration, equipment OEE, and to confirm REI start time.',
    `application_method` STRING COMMENT 'The agronomic method used to apply the fertilizer to the field or crop. Determines nutrient placement efficiency and environmental risk profile. [ENUM-REF-CANDIDATE: broadcast|banded|side_dress|fertigation|foliar|injection|top_dress — promote to reference product]',
    `application_start_timestamp` TIMESTAMP COMMENT 'Precise date and time when the fertilizer application operation began in the field. Sourced from John Deere Operations Center or Trimble Ag telematics. Used for REI (Restricted Entry Interval) compliance and equipment utilization analysis.',
    `application_status` STRING COMMENT 'Current lifecycle status of the fertilization event workflow. planned indicates a scheduled event not yet executed; in_progress indicates active application; completed indicates successful execution; cancelled indicates the event was called off before execution; voided indicates a data correction.. Valid values are `planned|in_progress|completed|cancelled|voided`',
    `application_type` STRING COMMENT 'Agronomic timing classification of the fertilizer application relative to the crop growth stage. Distinguishes pre-plant, at-plant, and in-season applications for nutrient management planning and compliance. [ENUM-REF-CANDIDATE: pre_plant|at_plant|side_dress|top_dress|in_season|post_harvest — promote to reference product]. Valid values are `pre_plant|at_plant|side_dress|top_dress|in_season|post_harvest`',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this fertilization event record was first created in the system. Serves as the audit creation timestamp for data governance, lineage tracking, and Silver layer ingestion auditing.',
    `event_number` STRING COMMENT 'Externally-known business identifier for the fertilization event, used in field records, agronomic reports, and regulatory submissions. Format: FERT-{YEAR}-{SEQUENCE}.. Valid values are `^FERT-[0-9]{4}-[0-9]{6}$`',
    `fertilizer_form` STRING COMMENT 'Physical form of the fertilizer product applied. Determines equipment requirements, handling procedures, and SDS (Safety Data Sheet) compliance. [ENUM-REF-CANDIDATE: dry_granular|liquid|anhydrous_ammonia|suspension|slow_release|controlled_release — promote to reference product]. Valid values are `dry_granular|liquid|anhydrous_ammonia|suspension|slow_release|controlled_release`',
    `is_gmo_derived` BOOLEAN COMMENT 'Indicates whether the fertilizer product contains or is derived from GMO (Genetically Modified Organism) sources (e.g., certain biofertilizers). Relevant for organic certification exclusion and international export compliance.',
    `is_organic` BOOLEAN COMMENT 'Indicates whether the fertilizer product applied is certified organic under the USDA National Organic Program (NOP). True = organic-approved input; False = conventional synthetic fertilizer. Critical for organic certification compliance and audit trails.',
    `is_vra_applied` BOOLEAN COMMENT 'Indicates whether this fertilization event was executed using Variable Rate Application (VRA) technology, applying different rates across management zones within the field. True = VRA prescription followed; False = flat-rate uniform application.',
    `last_updated_timestamp` TIMESTAMP COMMENT 'Date and time when this fertilization event record was most recently modified. Used for change data capture (CDC), Silver layer incremental loads, and audit trail compliance.',
    `nitrogen_applied_lbs_acre` DECIMAL(18,2) COMMENT 'Actual pounds of elemental nitrogen applied per acre during this event, derived from actual_rate and nitrogen_pct. Stored as a raw field value from the source system for EPA nutrient management plan compliance and environmental reporting. Critical KPI for nitrogen use efficiency (NUE) analysis.',
    `nitrogen_pct` DECIMAL(18,2) COMMENT 'Percentage of nitrogen (N) in the NPK formulation of the fertilizer product applied. Used for nutrient budget calculations, soil nitrogen loading analysis, and EPA nutrient management plan compliance.',
    `notes` STRING COMMENT 'Free-text field for operator or agronomist notes related to this fertilization event. May include observations about field conditions, equipment issues, deviations from prescription, or agronomic rationale. Supports GAP documentation requirements.',
    `nutrient_management_plan_ref` STRING COMMENT 'Reference number or identifier of the USDA NRCS-approved Nutrient Management Plan (NMP) that governs this fertilization event. Required for USDA conservation program compliance (e.g., EQIP) and EPA nutrient management reporting.',
    `phosphorus_pct` DECIMAL(18,2) COMMENT 'Percentage of phosphorus (P2O5) in the NPK formulation of the fertilizer product applied. Used for phosphorus loading calculations, water quality compliance, and soil nutrient balance reporting.',
    `planned_rate` DECIMAL(18,2) COMMENT 'The target or prescribed fertilizer application rate as specified in the agronomic plan or VRA prescription, expressed in the unit defined by rate_unit. Represents the intended nutrient loading before actual application.',
    `potassium_pct` DECIMAL(18,2) COMMENT 'Percentage of potassium (K2O) in the NPK formulation of the fertilizer product applied. Used for potassium budget calculations and soil fertility management reporting.',
    `rate_unit` STRING COMMENT 'Unit of measure for both planned_rate and actual_rate fields. Common units include lbs/acre (CWT-based), gallons/acre for liquid fertilizers, and metric equivalents for international operations.. Valid values are `lbs_per_acre|gal_per_acre|kg_per_ha|L_per_ha|cwt_per_acre|oz_per_acre`',
    `rei_expiry_timestamp` TIMESTAMP COMMENT 'Date and time when the Restricted Entry Interval (REI) expires following the fertilizer application, after which workers may safely re-enter the treated field. Calculated from application_end_timestamp plus the product-specific REI duration. Critical for OSHA and EPA worker safety compliance.',
    `soil_temperature_f` DECIMAL(18,2) COMMENT 'Soil temperature in degrees Fahrenheit at the time of fertilizer application. Critical for nitrogen application timing decisions (e.g., nitrification inhibitor effectiveness, anhydrous ammonia fall application restrictions) and nutrient uptake efficiency.',
    `source_system` STRING COMMENT 'Identifies the operational system of record from which this fertilization event record was sourced. Supports data lineage, reconciliation, and Silver layer ingestion audit for the Databricks Lakehouse pipeline.. Valid values are `john_deere_ops_center|trimble_ag|climate_fieldview|granular|manual_entry`',
    `source_system_event_reference` STRING COMMENT 'The native identifier of this fertilization event record in the originating operational system (e.g., John Deere Operations Center task ID, Trimble Ag field activity ID). Enables deduplication and reconciliation between the Silver layer and source systems.',
    `total_product_applied` DECIMAL(18,2) COMMENT 'Total quantity of fertilizer product applied across the entire treated area during this event, expressed in the unit defined by rate_unit. Calculated from actual_rate multiplied by treated_area_acres but stored as a raw field value from the source system for inventory reconciliation and nutrient management reporting.',
    `treated_area_acres` DECIMAL(18,2) COMMENT 'The actual field area covered by the fertilizer application, measured in acres. May differ from the total field area if only a portion of the field was treated. Sourced from GPS/RTK boundary data in John Deere Operations Center.',
    `weather_condition` STRING COMMENT 'Observed weather condition at the time of fertilizer application. Relevant for assessing nutrient runoff risk, volatilization potential, and GAP compliance. Recorded by the operator or sourced from field weather station data.. Valid values are `clear|cloudy|light_rain|windy|foggy|overcast`',
    `wind_speed_mph` DECIMAL(18,2) COMMENT 'Wind speed in miles per hour recorded at the time of fertilizer application. Used to assess drift risk for liquid and granular applications and to validate compliance with application label restrictions.',
    CONSTRAINT pk_fertilization_event PRIMARY KEY(`fertilization_event_id`)
) COMMENT 'Transactional record of a fertilizer application event on a field, capturing application date, product applied (NPK formulation), application rate (lbs/acre or gallons/acre), application method (broadcast, banded, fertigation), equipment used, operator, and VRA prescription reference. Tracks actual vs. planned nutrient application for agronomic compliance and environmental reporting (EPA nutrient management). Sourced from John Deere Operations Center and Trimble Ag.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`protection_event` (
    `protection_event_id` BIGINT COMMENT 'Primary key for protection_event',
    `agrochemical_product_id` BIGINT COMMENT 'Reference to the registered pesticide, herbicide, fungicide, or insecticide product master record used in this application event. Carries EPA registration number, active ingredient (AI), and label details.',
    `workforce_certification_id` BIGINT COMMENT 'Foreign key linking to workforce.workforce_certification. Business justification: WPS/EPA regulatory compliance: EPA and Worker Protection Standard regulations require the pesticide applicators license to be verified and recorded for each application event. protection_event has de',
    `asset_id` BIGINT COMMENT 'Reference to the application equipment (sprayer, drone, aerial applicator, or ground rig) used to perform the crop protection event. Supports equipment calibration records and OEE tracking.',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: Crop protection events apply a specific agrochemical lot. Linking to commodity_lot enables lot-level pesticide traceability, PHI/MRL compliance reporting, and EPA regulatory audit trails. lot_number o',
    `crop_id` BIGINT COMMENT 'Reference to the crop variety or commodity being protected during this application event. Used to validate Pre-Harvest Interval (PHI) compliance and Maximum Residue Limit (MRL) thresholds for the specific crop.',
    `field_crop_plan_id` BIGINT COMMENT 'Foreign key linking to crop.field_crop_plan. Business justification: protection_event has no link to field_crop_plan, yet crop protection activities are planned and governed by the field crop plans IPM program (ipm_program_id on field_crop_plan). Adding field_crop_pla',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field or management zone where the crop protection application event was performed. Links to the field master record containing parcel boundaries, soil data, and crop assignment.',
    `growing_season_id` BIGINT COMMENT 'Foreign key linking to crop.growing_season. Business justification: protection_event currently has no FK to growing_season, creating a gap in the agronomic event lifecycle. Every pesticide, herbicide, fungicide, or insecticide application occurs within a specific grow',
    `lab_sample_id` BIGINT COMMENT 'Foreign key linking to quality.lab_sample. Business justification: Post-application residue testing is a regulatory requirement: lab samples verify MRL compliance and PHI adherence after crop protection applications. FSMA and export market compliance depend on linkin',
    `permit_id` BIGINT COMMENT 'Foreign key linking to compliance.permit. Business justification: NPDES pesticide general permits and state restricted-use pesticide permits must be cited on application records. Linking protection_event to the governing permit enables permit condition compliance ve',
    `employee_id` BIGINT COMMENT 'Reference to the certified pesticide application operator or licensed agronomist who performed or supervised the crop protection event. Used for operator certification compliance tracking.',
    `purchase_order_id` BIGINT COMMENT 'Foreign key linking to procurement.purchase_order. Business justification: EPA and MRL compliance audits require traceability from agrochemical application events to the procurement PO confirming the product was legally sourced. This is a standard regulatory traceability req',
    `spray_window_id` BIGINT COMMENT 'Foreign key linking to weather.spray_window. Business justification: Pesticide/herbicide applications must occur within a compliant spray window (EPA drift constraints, wind speed, REI, temperature inversion). Linking protection_event to the authorizing spray_window is',
    `vra_prescription_id` BIGINT COMMENT 'Foreign key linking to crop.vra_prescription. Business justification: protection_event has no FK to vra_prescription, yet VRA prescriptions are commonly generated for variable-rate pesticide and herbicide applications based on scouting data and pest pressure maps. Addin',
    `active_ingredient` STRING COMMENT 'The chemical active ingredient (AI) in the applied pesticide product, as declared on the EPA-registered label. Used for MRL (Maximum Residue Limit) verification, Codex Alimentarius compliance, and IPM program tracking. May contain multiple AIs separated by semicolons.',
    `agronomist_signoff_date` DATE COMMENT 'Date on which the responsible agronomist reviewed and approved this crop protection event record. Mandatory for GLOBALG.A.P. CB 7.6 pesticide application record completeness and FSMA audit trail. Null indicates pending agronomist review.',
    `application_date` DATE COMMENT 'The calendar date on which the crop protection product was applied to the field. Principal business event date used to calculate PHI compliance (earliest harvest date) and REI field re-entry clearance date. Aligns with Climate FieldView spraying event date.',
    `application_end_time` TIMESTAMP COMMENT 'Precise timestamp when the crop protection application operation was completed. Combined with application_start_time to calculate total application duration and equipment utilization for OEE reporting.',
    `application_method` STRING COMMENT 'The physical method used to apply the crop protection product to the field or crop. Determines equipment calibration requirements, drift risk assessment, and label compliance. Sourced from Trimble Ag VRA prescription or Climate FieldView spraying records.. Valid values are `broadcast_spray|band_application|aerial|drip_chemigation|soil_incorporation|seed_treatment`',
    `application_rate` DECIMAL(18,2) COMMENT 'The quantity of crop protection product applied per unit area (e.g., oz/acre, L/ha, kg/ha) as prescribed on the EPA label. Must not exceed label maximum rate. Used for MRL compliance calculation and VRA (Variable Rate Application) prescription validation.',
    `application_rate_unit` STRING COMMENT 'Unit of measure for the application rate field, specifying the quantity and area basis (e.g., oz/acre, L/ha). Required for MRL compliance calculations and cross-regional reporting. Must align with the EPA-registered label unit. [ENUM-REF-CANDIDATE: oz/acre|fl_oz/acre|lb/acre|kg/ha|L/ha|mL/ha|pt/acre|qt/acre — 8 candidates stripped; promote to reference product]',
    `application_start_time` TIMESTAMP COMMENT 'Precise timestamp when the crop protection application operation commenced. Used for REI (Restricted Entry Interval) calculation, operator exposure tracking, and OSHA compliance. Sourced from John Deere Operations Center or Trimble Ag telematics.',
    `application_status` STRING COMMENT 'Current lifecycle workflow status of the crop protection application event. Drives PHI compliance checks, agronomist sign-off workflows, and FSMA audit readiness. pending_review indicates awaiting agronomist approval.. Valid values are `planned|in_progress|completed|cancelled|pending_review`',
    `application_type` STRING COMMENT 'Classification of the crop protection product by its mode of action or target pest category. Drives IPM program reporting, EPA pesticide use reporting, and GLOBALG.A.P. pesticide audit trail categorization. [ENUM-REF-CANDIDATE: herbicide|fungicide|insecticide|nematicide|rodenticide|plant_growth_regulator|bactericide|acaricide|molluscicide — promote to reference product]. Valid values are `herbicide|fungicide|insecticide|nematicide|rodenticide|plant_growth_regulator`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this crop protection event record was first captured in the system of record. Supports audit trail requirements under FSMA, GLOBALG.A.P., and EPA pesticide recordkeeping regulations.',
    `earliest_harvest_date` DATE COMMENT 'Calculated earliest date on which the treated crop may be harvested in compliance with the PHI (Pre-Harvest Interval). Computed as application_date + phi_days_required. Enforced in harvest scheduling to prevent MRL violations and FSMA non-compliance.',
    `epa_registration_number` STRING COMMENT 'EPA registration number of the pesticide product applied, as printed on the product label. Mandatory for FIFRA compliance recordkeeping. Format: registrant-product[-state suffix]. Must match the EPA-registered label used at time of application.. Valid values are `^[0-9]{5}-[0-9]{3,5}(-[A-Z]{2})?$`',
    `event_number` STRING COMMENT 'Externally-known business identifier for this crop protection application event, formatted as CPE-{YEAR}-{SEQUENCE}. Used in audit trails, GLOBALG.A.P. pesticide records, EPA recordkeeping submissions, and FSMA traceability documentation.. Valid values are `^CPE-[0-9]{4}-[0-9]{6}$`',
    `gps_coverage_polygon` STRING COMMENT 'Well-Known Text (WKT) representation of the GPS-tracked coverage polygon for this application event, as recorded by John Deere Operations Center or Trimble RTK positioning. Enables GIS-based spatial analysis in Esri ArcGIS for drift buffer compliance and field coverage verification.',
    `ipm_justified` BOOLEAN COMMENT 'Indicates whether this crop protection application was justified by an IPM (Integrated Pest Management) scouting threshold or economic injury level assessment, rather than a calendar-based schedule. True = IPM threshold-triggered; False = preventive/calendar application. Required for GLOBALG.A.P. IPM program compliance.',
    `phi_compliance_status` STRING COMMENT 'Compliance determination for the PHI requirement relative to the planned harvest date. compliant = harvest date is after earliest_harvest_date; non_compliant = harvest scheduled before PHI expiry; pending = harvest date not yet confirmed; waived = regulatory exemption applied.. Valid values are `compliant|non_compliant|pending|waived`',
    `phi_days_required` STRING COMMENT 'Number of days that must elapse between the last application of this crop protection product and the earliest permissible harvest date, as specified on the EPA-registered label. Core compliance field for FSMA, GLOBALG.A.P., and MRL verification.',
    `rei_clearance_datetime` TIMESTAMP COMMENT 'Calculated datetime after which workers may safely re-enter the treated field, computed as application_start_time + rei_hours_required. Posted at field entry points per EPA Worker Protection Standard. Critical for OSHA and EPA WPS compliance.',
    `rei_compliance_status` STRING COMMENT 'Compliance determination for the REI requirement. compliant = no worker re-entry before rei_clearance_datetime; non_compliant = documented early re-entry violation; pending = REI period still active; waived = PPE exception per label.. Valid values are `compliant|non_compliant|pending|waived`',
    `rei_hours_required` DECIMAL(18,2) COMMENT 'Number of hours that workers must stay out of the treated field following application, as specified on the EPA-registered label under the Worker Protection Standard (WPS). Decimal to support half-hour increments (e.g., 4.0, 12.0, 24.0, 48.0 hours).',
    `relative_humidity_pct` DECIMAL(18,2) COMMENT 'Relative humidity percentage at the time of application. Low humidity increases evaporation and drift risk for certain pesticide formulations. Required for label compliance documentation and GLOBALG.A.P. application condition records.',
    `target_pest` STRING COMMENT 'The specific pest, weed, disease, or pathogen that the crop protection application was intended to control, as identified through IPM scouting. Examples: Fusarium head blight, corn rootworm, Palmer amaranth. Supports IPM program efficacy tracking and GLOBALG.A.P. CB 7.2 pest monitoring records.',
    `temperature_c` DECIMAL(18,2) COMMENT 'Ambient air temperature in degrees Celsius at the time of application. High temperatures can increase volatilization and drift risk. Some EPA labels restrict application above threshold temperatures. Sourced from field weather station or Climate FieldView weather data.',
    `total_area_treated_ha` DECIMAL(18,2) COMMENT 'Total field area covered by this crop protection application event, measured in hectares. Derived from GPS-tracked equipment coverage via John Deere Operations Center or Trimble RTK positioning. Used for total product quantity reconciliation and EPA pesticide use reporting.',
    `total_product_used` DECIMAL(18,2) COMMENT 'Total quantity of crop protection product consumed in this application event (application_rate × total_area_treated). Expressed in the same unit as application_rate_unit. Used for inventory depletion in SAP S/4HANA MM and EPA pesticide use reporting.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this crop protection event record. Required for data lineage tracking in the Databricks Silver Layer and regulatory audit trail completeness.',
    `water_volume_rate` DECIMAL(18,2) COMMENT 'Volume of water carrier used per acre in the spray mixture (gallons/acre or L/ha). Critical for spray efficacy, equipment calibration validation, and label compliance. Sourced from sprayer controller data in John Deere Operations Center or Trimble Ag.',
    `wind_direction` STRING COMMENT 'Compass direction of wind at time of application (8-point compass rose). Used for pesticide drift risk assessment, buffer zone compliance, and neighbor notification requirements under EPA label conditions. [ENUM-REF-CANDIDATE: N|NE|E|SE|S|SW|W|NW — 8 candidates stripped; promote to reference product]',
    `wind_speed_mph` DECIMAL(18,2) COMMENT 'Measured wind speed in miles per hour at the time of application. EPA label restrictions typically prohibit application above 10-15 mph to prevent pesticide drift. Sourced from on-field weather station or John Deere Operations Center weather integration.',
    CONSTRAINT pk_protection_event PRIMARY KEY(`protection_event_id`)
) COMMENT 'Transactional record of a pesticide, herbicide, fungicide, or insecticide application event, capturing application date, agrochemical product reference (EPA registration number, active ingredient), application rate, target pest or disease, application method, equipment used, operator certification number, weather conditions at application, and GPS-tracked coverage area. Includes PHI (Pre-Harvest Interval) compliance tracking: PHI days required, calculated earliest harvest date, REI (Restricted Entry Interval) hours required, field re-entry clearance date, compliance status, and responsible agronomist sign-off. Supports IPM program execution, FSMA compliance, EPA pesticide recordkeeping, MRL verification, and GLOBALG.A.P. pesticide audit trails.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`irrigation_event` (
    `irrigation_event_id` BIGINT COMMENT 'Unique system-generated identifier for each irrigation application event record in the crop domain. Serves as the primary key for this transactional entity.',
    `employee_id` BIGINT COMMENT 'Reference to the farm operator or equipment operator who executed or supervised this irrigation event. Supports workforce accountability, GAP compliance, and training record linkage.',
    `equipment_field_operation_id` BIGINT COMMENT 'Foreign key linking to equipment.field_operation. Business justification: Irrigation events record water application volumes; field_operation records pump/pivot equipment execution. Linking enables water use efficiency reporting, energy cost allocation per irrigation event,',
    `field_crop_plan_id` BIGINT COMMENT 'Foreign key linking to crop.field_crop_plan. Business justification: irrigation_event links to growing_season and weather data but has no FK to field_crop_plan. The field crop plan defines irrigation targets (irrigation_system_type, irrigation_target_depth_inches, wate',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field or management zone on which this irrigation event was applied. Links to the field master record in the crop domain.',
    `growing_season_id` BIGINT COMMENT 'Reference to the crop growing season during which this irrigation event occurred, enabling season-level water use aggregation and agronomic analysis.',
    `irrigation_schedule_id` BIGINT COMMENT 'Identifier of the variable rate application (VRA) prescription or irrigation schedule from Trimble Ag Software or Climate FieldView that directed this irrigation event. Enables planned vs. actual analysis.',
    `irrigation_zone_id` BIGINT COMMENT 'Foreign key linking to land.irrigation_zone. Business justification: Irrigation events are executed within irrigation zones that define system type, permitted volume, and water right. Water right compliance reporting requires tracking volume applied per zone against pe',
    `pump_station_id` BIGINT COMMENT 'Reference to the pump station or irrigation infrastructure unit that delivered water for this event, supporting equipment utilization and maintenance tracking.',
    `station_id` BIGINT COMMENT 'Identifier of the weather station whose data was used to calculate ET trigger values and inform irrigation scheduling for this event. Supports traceability of agronomic decisions.',
    `vra_prescription_id` BIGINT COMMENT 'Foreign key linking to crop.vra_prescription. Business justification: irrigation_event has no FK to vra_prescription, yet VRA prescriptions can govern variable-rate irrigation applications (input_type on vra_prescription covers irrigation). Adding vra_prescription_id to',
    `work_order_id` BIGINT COMMENT 'Reference to the SAP S/4HANA work order or field operation task that authorized and scheduled this irrigation event.',
    `actual_duration_minutes` STRING COMMENT 'Actual elapsed time of the irrigation event in minutes, derived from start and end timestamps or IoT sensor telemetry. Used for operational efficiency analysis and equipment OEE calculations.',
    `application_date` DATE COMMENT 'Calendar date on which the irrigation was applied. Used for day-level scheduling, PHI compliance checks, regulatory water use reporting, and agronomic calendar alignment.',
    `application_rate_inches_per_hour` DECIMAL(18,2) COMMENT 'Rate at which water was applied during this irrigation event, measured in inches per hour. Used to assess runoff risk, soil infiltration compliance, and equipment calibration validation per USDA NRCS guidelines.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this irrigation event record was first created in the system. Supports audit trail, data lineage, and Silver Layer ingestion tracking.',
    `crop_growth_stage` STRING COMMENT 'Growth stage of the crop at the time of irrigation (e.g., germination, vegetative, flowering, grain fill, maturity). Critical for ET coefficient (Kc) selection, water demand modeling, and agronomic decision support.',
    `data_source` STRING COMMENT 'Originating system or method by which this irrigation event record was captured. Supports data lineage, quality assessment, and FMIS integration traceability in the Silver Layer.. Valid values are `john_deere_ops_center|climate_fieldview|trimble_ag|manual_entry|iot_sensor|granular`',
    `distribution_uniformity_pct` DECIMAL(18,2) COMMENT 'Coefficient of distribution uniformity (DU%) for this irrigation event, measuring how evenly water was applied across the field or zone. Key BMP metric for irrigation system performance and GLOBALG.A.P. compliance.',
    `end_timestamp` TIMESTAMP COMMENT 'Date and time when the irrigation application concluded. Used with start_timestamp to calculate actual duration and validate against planned duration for operational efficiency analysis.',
    `energy_cost_usd` DECIMAL(18,2) COMMENT 'Estimated or actual energy cost in US dollars for pumping water during this irrigation event. Used for OPEX analysis, energy efficiency benchmarking, and sustainability reporting.',
    `et_trigger_value_inches` DECIMAL(18,2) COMMENT 'Evapotranspiration (ET) deficit value in inches that triggered this irrigation event, as calculated from weather station data or crop model. Core metric for ET-driven irrigation scheduling and water use efficiency reporting.',
    `event_number` STRING COMMENT 'Externally-known business identifier for this irrigation event, formatted as IRR-{YYYY}-{NNNNNN}. Used for field operations tracking, BMP compliance reporting, and cross-system reference in FMIS and John Deere Operations Center.. Valid values are `^IRR-[0-9]{4}-[0-9]{6}$`',
    `event_status` STRING COMMENT 'Current lifecycle status of the irrigation event, tracking progression from scheduled through execution to completion or cancellation. Supports operational workflow management and reporting.. Valid values are `scheduled|in_progress|completed|cancelled|aborted`',
    `flow_rate_gpm` DECIMAL(18,2) COMMENT 'Measured flow rate of water delivery in gallons per minute (GPM) during this irrigation event. Used for pump performance analysis, water meter reconciliation, and system efficiency reporting.',
    `irrigation_method` STRING COMMENT 'Type of irrigation delivery system used for this event. Determines water use efficiency benchmarks, BMP compliance classification, and equipment utilization reporting. [ENUM-REF-CANDIDATE: drip|center_pivot|flood|sprinkler|subsurface_drip|furrow|micro_sprinkler|lateral_move — promote to reference product if additional methods are needed]. Valid values are `drip|center_pivot|flood|sprinkler|subsurface_drip|furrow`',
    `is_bmp_compliant` BOOLEAN COMMENT 'Indicates whether this irrigation event was conducted in accordance with Best Management Practices (BMP) as defined by USDA NRCS and applicable state environmental agencies. Required for conservation program reporting.',
    `is_scheduled` BOOLEAN COMMENT 'Indicates whether this irrigation event was executed as part of a pre-planned schedule (True) or was an unplanned/emergency application (False). Used for schedule adherence reporting and agronomic audit trails.',
    `notes` STRING COMMENT 'Free-text field for operator or agronomist observations related to this irrigation event, such as equipment anomalies, field conditions, or agronomic observations not captured in structured fields.',
    `planned_duration_minutes` STRING COMMENT 'Scheduled duration of the irrigation event in minutes as defined in the irrigation prescription or FMIS schedule. Used for variance analysis against actual duration.',
    `pressure_psi` DECIMAL(18,2) COMMENT 'Operating pressure of the irrigation system in pounds per square inch (PSI) during this event. Used for equipment performance monitoring, uniformity assessment, and maintenance scheduling.',
    `rainfall_since_last_event_inches` DECIMAL(18,2) COMMENT 'Total precipitation in inches recorded between the previous irrigation event and this one. Used to adjust effective irrigation need, validate ET-based scheduling decisions, and support water use efficiency reporting.',
    `soil_moisture_pct_after` DECIMAL(18,2) COMMENT 'Volumetric soil moisture content (%) recorded by IoT sensors following irrigation application. Used to assess irrigation effectiveness, field capacity attainment, and over-irrigation risk.',
    `soil_moisture_pct_before` DECIMAL(18,2) COMMENT 'Volumetric soil moisture content (%) recorded by IoT sensors immediately prior to irrigation application. Used to validate ET-based trigger thresholds and assess irrigation necessity per BMP standards.',
    `soil_moisture_sensor_depth_cm` STRING COMMENT 'Depth in centimeters at which the soil moisture sensor reading was taken. Required for agronomic interpretation of moisture data and root zone analysis.',
    `start_timestamp` TIMESTAMP COMMENT 'Date and time when the irrigation application began. Principal business event timestamp for this transaction, used for ET-driven scheduling analysis, water use reporting, and IoT sensor correlation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp of the most recent modification to this irrigation event record. Supports change tracking, data quality monitoring, and audit compliance in the Databricks Silver Layer.',
    `volume_applied_acre_inches` DECIMAL(18,2) COMMENT 'Total volume of water applied during this irrigation event, measured in acre-inches. Primary quantitative outcome for water use reporting, ET-based scheduling validation, and BMP compliance under USDA NRCS standards.',
    `volume_applied_gallons` DECIMAL(18,2) COMMENT 'Total volume of water applied during this irrigation event, expressed in US gallons. Supports pump station metering reconciliation, water rights reporting, and utility billing where applicable.',
    `water_cost_usd` DECIMAL(18,2) COMMENT 'Estimated or actual cost of water applied during this irrigation event in US dollars, based on metered usage rates, well pumping costs, or municipal water tariffs. Supports COGS allocation and OPEX reporting.',
    `water_source_name` STRING COMMENT 'Descriptive name or identifier of the specific water source used (e.g., well name, canal name, reservoir name, municipal supply ID). Supports water rights tracking and regulatory reporting.',
    `water_source_type` STRING COMMENT 'Classification of the water source used for this irrigation event. Required for water rights compliance, environmental reporting, and BMP documentation under USDA and EPA frameworks.. Valid values are `groundwater|surface_water|recycled|municipal|rainwater_harvest`',
    CONSTRAINT pk_irrigation_event PRIMARY KEY(`irrigation_event_id`)
) COMMENT 'Transactional record of an irrigation application on a field or zone, capturing irrigation date, method (drip, pivot, flood, sprinkler), water volume applied (acre-inches), ET-based trigger value, soil moisture reading at time of application, water source, pump station reference, and duration. Supports ET-driven irrigation scheduling, water use reporting, and BMP compliance. Integrates with IoT soil moisture sensors and John Deere Operations Center.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`scouting_observation` (
    `scouting_observation_id` BIGINT COMMENT 'Unique system-generated identifier for each field scouting observation record. Serves as the primary key for the scouting_observation data product within the crop domain.',
    `asset_id` BIGINT COMMENT 'Foreign key linking to equipment.asset. Business justification: Scouting observations are collected using UAVs, sensor ATVs, or other precision ag equipment. Linking identifies which asset collected the data, supporting equipment utilization reporting, calibration',
    `crop_id` BIGINT COMMENT 'Reference to the crop variety or species being scouted in the field at the time of observation. Links to the crop master record in the crop management domain.',
    `protection_event_id` BIGINT COMMENT 'Reference to the crop protection event created as a result of this scouting observation. Establishes the traceability link between IPM observation and the resulting pesticide or treatment application record.',
    `equipment_field_operation_id` BIGINT COMMENT 'Foreign key linking to equipment.field_operation. Business justification: Scouting observations generated by drone or sensor field operations must be traceable to the executing field operation for IPM documentation, data quality audits, and precision ag compliance reporting',
    `field_crop_plan_id` BIGINT COMMENT 'Foreign key linking to crop.field_crop_plan. Business justification: scouting_observation links to growing_season and protection_event but has no FK to field_crop_plan. Scouting observations are conducted to monitor crop health against the IPM program defined in the fi',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field or management zone where the scouting observation was conducted. Links to the land and soil domain field master record.',
    `growing_season_id` BIGINT COMMENT 'Reference to the growing season or crop year during which this scouting observation was recorded. Enables seasonal trend analysis and year-over-year IPM benchmarking.',
    `inspection_id` BIGINT COMMENT 'Foreign key linking to quality.inspection. Business justification: Field scouting observations serve as objective evidence during GAP field inspections. Inspectors reference scouting records to verify IPM compliance, pest pressure documentation, and food safety risk ',
    `management_zone_id` BIGINT COMMENT 'Foreign key linking to land.management_zone. Business justification: IPM programs track pest pressure and incidence by management zone to trigger zone-specific interventions. Scouting observations are spatially recorded at zone level for precision pest management repor',
    `employee_id` BIGINT COMMENT 'Reference to the agronomist, crop scout, or remote sensing operator who conducted or submitted the observation. Links to the workforce domain employee or contractor record.',
    `vra_prescription_id` BIGINT COMMENT 'Reference to the Variable Rate Application prescription generated as a result of this scouting observation. Links the observation to precision agriculture intervention decisions in Trimble Ag Software.',
    `observation_id` BIGINT COMMENT 'Foreign key linking to weather.observation. Business justification: Scouting observations record weather_conditions as denormalized text. Linking to the actual weather observation record supports pest pressure modeling, disease risk correlation (leaf wetness, humidity',
    `action_due_date` DATE COMMENT 'Target date by which the recommended follow-up action should be completed. Calculated considering PHI (Pre-Harvest Interval), REI (Restricted Entry Interval), and crop growth stage urgency. Used for workflow scheduling in SAP S/4HANA PP.',
    `anomaly_detected` BOOLEAN COMMENT 'Indicates whether an anomaly was detected in the vegetation index or field condition relative to the seasonal baseline or surrounding field zones. True triggers priority review and potential VRA prescription adjustment.',
    `bbch_growth_stage_code` STRING COMMENT 'Crop growth stage at the time of observation expressed using the BBCH (Biologische Bundesanstalt, Bundessortenamt und CHemische Industrie) decimal scale (00–99). Critical for PHI and REI compliance calculations and timing of crop protection applications.. Valid values are `^[0-9]{2}$`',
    `created_timestamp` TIMESTAMP COMMENT 'System timestamp recording when the scouting observation record was first created in the FMIS or data platform. Used for data lineage, audit trail, and SLA compliance tracking.',
    `gps_accuracy_m` DECIMAL(18,2) COMMENT 'Estimated horizontal positional accuracy of the GPS coordinates in meters at the time of observation. RTK-corrected readings typically achieve sub-0.05m accuracy; standard GPS may be 3–5m. Used to qualify spatial data reliability.',
    `imagery_date` DATE COMMENT 'Date on which the remote sensing imagery used for this observation was captured. May differ from observation_timestamp if imagery was analyzed retrospectively. Used for temporal alignment in seasonal vegetation health comparisons.',
    `incidence_pct` DECIMAL(18,2) COMMENT 'Percentage of sampled plants or area units showing presence of the observed pest, disease, or weed (0.00–100.00). Quantitative measure used alongside pressure rating for economic threshold analysis and IPM action decisions.',
    `latitude` DECIMAL(18,2) COMMENT 'GPS latitude coordinate (WGS84 decimal degrees) of the precise location within the field where the observation was recorded. Enables GIS-based spatial analysis and precision agriculture mapping in Esri ArcGIS.',
    `longitude` DECIMAL(18,2) COMMENT 'GPS longitude coordinate (WGS84 decimal degrees) of the precise location within the field where the observation was recorded. Used alongside latitude for spatial clustering and VRA zone delineation.',
    `ndvi_baseline_delta` DECIMAL(18,2) COMMENT 'Difference between the current NDVI value and the seasonal historical baseline NDVI for the same field zone and growth stage. Positive values indicate improvement; negative values indicate decline relative to baseline.',
    `ndvi_value` DECIMAL(18,2) COMMENT 'Normalized Difference Vegetation Index value ranging from -1.0000 to 1.0000 derived from remote sensing imagery. Values above 0.6 indicate healthy dense vegetation; values below 0.3 indicate stressed or sparse vegetation. Null for in-person observations without sensor data.',
    `nutrient_deficiency_type` STRING COMMENT 'Type of nutrient deficiency symptom observed on the crop. Applicable when observation_category is nutrient_deficiency. Aligned with NPK (Nitrogen, Phosphorus, Potassium) and micronutrient classification. [ENUM-REF-CANDIDATE: nitrogen|phosphorus|potassium|sulfur|iron|zinc|manganese|boron — promote to reference product]',
    `observation_category` STRING COMMENT 'Primary classification of what was observed during the scouting event. Segments observations for IPM reporting, crop protection event triggers, and VRA prescription generation. [ENUM-REF-CANDIDATE: pest|disease|weed|nutrient_deficiency|crop_health|vegetation_index|soil_condition|irrigation_stress — promote to reference product]',
    `observation_method` STRING COMMENT 'Discriminator indicating how the scouting observation was collected: in-person field walk, satellite remote sensing, drone/UAV aerial imagery, manned aerial survey, or IoT sensor reading. Drives downstream processing logic and data quality rules.. Valid values are `in_person|satellite_remote_sensing|drone_aerial|aerial_manned|iot_sensor`',
    `observation_number` STRING COMMENT 'Externally-known business identifier for the scouting observation, formatted as SCO-{YEAR}-{SEQUENCE}. Used for cross-referencing with Trimble Ag Software, Climate FieldView, and SAP S/4HANA PP crop protection events.. Valid values are `^SCO-[0-9]{4}-[0-9]{6}$`',
    `observation_status` STRING COMMENT 'Current lifecycle state of the scouting observation record, from initial field capture through agronomist review, action assignment, and closure. Drives workflow routing in Trimble Ag Software and SAP S/4HANA PP.. Valid values are `draft|submitted|reviewed|actioned|closed|voided`',
    `observation_timestamp` TIMESTAMP COMMENT 'The precise date and time when the scouting observation was made in the field or when remote sensing imagery was captured. Principal real-world event time used for IPM decision timing and PHI/REI compliance tracking.',
    `observer_notes` STRING COMMENT 'Free-text field notes recorded by the agronomist or scout during the observation. Captures qualitative context, unusual conditions, or supplementary observations not captured in structured fields. Stored for audit and agronomic review.',
    `pest_common_name` STRING COMMENT 'Common name of the pest, disease, or weed species identified during the scouting observation (e.g., Corn Rootworm, Soybean Rust, Waterhemp). Complements the scientific code for field-user readability.',
    `pest_organism_code` STRING COMMENT 'Standardized scientific or EPPO (European and Mediterranean Plant Protection Organization) code identifying the pest species, disease pathogen, or weed species observed. Null when observation category is not pest, disease, or weed.',
    `photo_reference_url` STRING COMMENT 'URL or file path reference to photographic evidence captured during the scouting observation. Photos are stored in the enterprise document management system and linked here for audit trail and agronomist review purposes.',
    `pressure_rating` STRING COMMENT 'Qualitative rating of pest or disease pressure intensity observed in the field, ranging from none to severe. Used as the primary IPM decision trigger for crop protection event initiation and economic threshold comparison.. Valid values are `none|trace|low|moderate|high|severe`',
    `priority` STRING COMMENT 'Priority level assigned to the scouting observation indicating urgency of follow-up action. Critical and high priorities trigger immediate crop protection event creation or VRA prescription review in the FMIS.. Valid values are `critical|high|medium|low`',
    `recommended_action` STRING COMMENT 'Recommended agronomic action based on the scouting observation findings. Drives downstream workflow creation in SAP S/4HANA PP for crop protection events or Trimble Ag Software for VRA prescriptions. [ENUM-REF-CANDIDATE: no_action|monitor|apply_crop_protection|adjust_irrigation|apply_fertilizer|vra_prescription|escalate_agronomist — promote to reference product]',
    `review_timestamp` TIMESTAMP COMMENT 'Date and time when the scouting observation was reviewed and validated by the responsible agronomist or supervisor. Part of the IPM audit trail required by GLOBALG.A.P. and FSMA compliance frameworks.',
    `sample_count` STRING COMMENT 'Number of individual plant samples, transects, or observation points assessed during the scouting event. Provides statistical context for incidence and severity ratings and supports data quality validation.',
    `scouted_area_ha` DECIMAL(18,2) COMMENT 'Total area of the field covered by this scouting observation, expressed in hectares. Used to calculate observation density, extrapolate field-wide pest pressure, and determine VRA prescription zone boundaries.',
    `sensor_platform` STRING COMMENT 'The sensor or imaging platform used to capture remote sensing data for this observation (e.g., satellite, drone/UAV, manned aerial, ground-based IoT sensor, handheld device). Null for purely in-person observations without sensor data.. Valid values are `satellite|drone_uav|manned_aerial|ground_sensor|handheld_device`',
    `severity_rating` STRING COMMENT 'Qualitative rating of the severity of damage or infection on affected plants, distinct from incidence (which measures spread). Severity measures the degree of impact on individual plants. Used in conjunction with incidence_pct for full IPM assessment.. Valid values are `none|trace|low|moderate|high|severe`',
    `updated_timestamp` TIMESTAMP COMMENT 'System timestamp recording when the scouting observation record was most recently modified. Supports data lineage tracking, change detection in the Databricks Silver Layer, and audit compliance.',
    `vegetation_health_class` STRING COMMENT 'Classified vegetation health category derived from NDVI or other spectral indices. Used for field-level health mapping, anomaly detection, and seasonal baseline comparison in Climate FieldView and Esri ArcGIS.. Valid values are `healthy|stressed|moderate_stress|severe_stress|bare_soil|water`',
    `weed_density_per_sqm` DECIMAL(18,2) COMMENT 'Count of weed plants per square meter observed in the scouted area. Applicable when observation_category is weed. Used to determine economic threshold for herbicide application and VRA prescription generation.',
    CONSTRAINT pk_scouting_observation PRIMARY KEY(`scouting_observation_id`)
) COMMENT 'Field observation record capturing crop health assessments from both in-person scouting and remote sensing sources. In-person scouting captures: agronomist or scout identity, pest identification and pressure rating, disease incidence and severity, weed species and density, nutrient deficiency symptoms, crop growth stage (BBCH scale code), GPS coordinates, photo references, and recommended action. Remote sensing captures: NDVI values, vegetation health classification, anomaly detection flags, seasonal baseline comparison, sensor platform (satellite, drone, aerial), and imagery date. Includes observation method type, priority classification, and recommended follow-up actions linking to crop protection events or VRA prescriptions. Sourced from Trimble Ag Software crop scouting module, Esri ArcGIS, and Climate FieldView. Drives IPM decision-making, crop protection event triggers, and variable rate intervention decisions.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`vra_prescription` (
    `vra_prescription_id` BIGINT COMMENT 'Unique system-generated identifier for the Variable Rate Application (VRA) prescription record. Serves as the primary key for this entity across all downstream systems and lakehouse layers.',
    `employee_id` BIGINT COMMENT 'Reference to the agronomist or certified crop advisor (CCA) who authored and approved this VRA prescription. Required for GAP compliance and regulatory audit trails.',
    `field_id` BIGINT COMMENT 'Reference to the specific agricultural field for which this VRA prescription was generated. Links to the field master record containing boundary geometry, acreage, and land unit details.',
    `growing_season_id` BIGINT COMMENT 'Reference to the crop season (growing year/season) for which this VRA prescription applies, enabling season-over-season agronomic comparison and input cost tracking.',
    `precision_device_id` BIGINT COMMENT 'Foreign key linking to equipment.precision_device. Business justification: VRA prescriptions are executed by specific variable-rate controllers or section control devices. Linking identifies the executing device to verify calibration compliance before prescription execution ',
    `seed_variety_id` BIGINT COMMENT 'Reference to the specific crop variety or hybrid for which this VRA prescription was designed, ensuring agronomic alignment between input rates and crop-specific nutrient or protection requirements.',
    `spray_window_id` BIGINT COMMENT 'Foreign key linking to weather.spray_window. Business justification: VRA prescriptions for pesticide/fertilizer applications specify target application windows that must align with compliant spray windows. Linking vra_prescription to the authorizing spray_window suppor',
    `superseded_by_vra_prescription_id` BIGINT COMMENT 'Reference to the newer VRA prescription that replaced this one when prescription_status is superseded. Enables forward-chaining of prescription revision history for agronomic audit and compliance documentation.',
    `zone_map_id` BIGINT COMMENT 'Reference to the management zone map used to delineate spatially variable application zones within the field. Zone maps are derived from soil sampling, NDVI imagery, yield history, or EC surveys.',
    `application_method` STRING COMMENT 'Method by which the prescribed input will be applied to the field. Determines equipment configuration, nozzle selection, and RTK guidance requirements for variable rate controllers. [ENUM-REF-CANDIDATE: broadcast|banded|foliar|injected|aerial|drip|fertigation — 7 candidates stripped; promote to reference product]',
    `approved_timestamp` TIMESTAMP COMMENT 'Date and time when the agronomist or authorized reviewer formally approved this VRA prescription for field use. Required for GAP compliance documentation and regulatory audit readiness.',
    `controller_upload_status` STRING COMMENT 'Status of the VRA prescription file upload to the RTK-enabled equipment controller (e.g., John Deere Operations Center, Trimble display). pending = awaiting upload; uploaded = file transferred; confirmed = controller acknowledged receipt; failed = upload error requiring retry.. Valid values are `pending|uploaded|confirmed|failed`',
    `controller_upload_timestamp` TIMESTAMP COMMENT 'Date and time when the VRA prescription file was successfully uploaded to the field equipment controller. Used for operational sequencing, equipment readiness verification, and audit trail documentation.',
    `created_timestamp` TIMESTAMP COMMENT 'Date and time when this VRA prescription record was first created in the system (Trimble Ag Software or Climate FieldView). Used for audit trail, version control, and FSMA traceability requirements.',
    `data_source_type` STRING COMMENT 'Primary type of agronomic data used to inform zone delineation and rate assignment for this VRA prescription. Indicates the scientific basis of the prescription for agronomic review and regulatory documentation. [ENUM-REF-CANDIDATE: soil_sampling|yield_history|ndvi_imagery|ec_survey|scouting|multi_source — promote to reference product if additional source types are needed]. Valid values are `soil_sampling|yield_history|ndvi_imagery|ec_survey|scouting|multi_source`',
    `default_rate` DECIMAL(18,2) COMMENT 'Baseline or average application rate for the entire field, expressed in the prescriptions rate_unit. Used as a fallback rate for zones without specific assignments and as a benchmark for VRA cost-benefit analysis.',
    `input_type` STRING COMMENT 'Classification of the agricultural input covered by this VRA prescription. Determines the applicable regulatory framework (EPA for crop protection, USDA for fertilizer/seed) and links to the correct application event type (planting_event, fertilization_event, or protection_event).. Valid values are `seed|fertilizer|crop_protection|lime|micronutrient`',
    `ipm_strategy_flag` BOOLEAN COMMENT 'Indicates whether this VRA prescription was developed as part of a formal Integrated Pest Management (IPM) program, where application rates are informed by economic thresholds and scouting data rather than calendar-based schedules. Required for EPA IPM compliance documentation and GLOBALG.A.P. certification.',
    `is_gmo_input` BOOLEAN COMMENT 'Indicates whether the input product specified in this VRA prescription is a Genetically Modified Organism (GMO) seed or GMO-derived product. Required for USDA APHIS biotech crop reporting, non-GMO certification programs, and COOL labeling compliance.',
    `is_organic_compliant` BOOLEAN COMMENT 'Indicates whether the input product and application method specified in this VRA prescription comply with USDA National Organic Program (NOP) standards. Required for certified organic operations and organic transition documentation.',
    `max_rate` DECIMAL(18,2) COMMENT 'Highest prescribed application rate across all management zones in this VRA prescription, expressed in rate_unit. Used for equipment controller calibration, input cost ceiling estimation, and regulatory compliance with label maximum rates.',
    `min_rate` DECIMAL(18,2) COMMENT 'Lowest prescribed application rate across all management zones in this VRA prescription, expressed in rate_unit. Used for equipment controller calibration, input cost floor estimation, and environmental compliance (MRL, runoff risk).',
    `notes` STRING COMMENT 'Free-text agronomic notes or special instructions associated with this VRA prescription, such as weather conditions required for application, equipment calibration reminders, or regulatory cautions. Captured by the agronomist at time of creation or approval.',
    `npk_target_ratio` STRING COMMENT 'Target Nitrogen-Phosphorus-Potassium (NPK) ratio for fertilizer VRA prescriptions, expressed in the standard N-P-K format (e.g., 46-0-0 for urea, 10-34-0 for liquid starter). Null for non-fertilizer prescriptions. Used for nutrient management plan compliance and soil health tracking.. Valid values are `^[0-9]{1,3}-[0-9]{1,3}-[0-9]{1,3}$`',
    `phi_days` STRING COMMENT 'Pre-Harvest Interval (PHI) in days as specified on the input product label, indicating the minimum number of days that must elapse between the last application and harvest. Critical for food safety compliance and MRL adherence. Applicable primarily to crop protection inputs.',
    `prescription_file_format` STRING COMMENT 'File format of the VRA prescription map exported for equipment controller upload. Common formats include ESRI Shapefile, ISO-XML (ISOBUS standard), GeoTIFF, and proprietary formats for Trimble, Climate FieldView, and John Deere Operations Center.. Valid values are `shapefile|iso_xml|geotiff|trimble_agx|climate_fieldview|john_deere_ops`',
    `prescription_name` STRING COMMENT 'Human-readable descriptive name for the VRA prescription, typically including field name, input type, and season (e.g., North 40 - Nitrogen VRA - Spring 2024). Used for identification in Trimble Ag Software and Climate FieldView dashboards.',
    `prescription_number` STRING COMMENT 'Externally-known business identifier for the VRA prescription, used in Trimble Ag Software and Climate FieldView for cross-system reference, field documentation, and equipment controller upload tracking.. Valid values are `^VRA-[A-Z0-9]{4,}-[0-9]{4,}$`',
    `prescription_status` STRING COMMENT 'Current lifecycle status of the VRA prescription. draft = under development; approved = agronomist-signed off; uploaded = sent to equipment controller; applied = field application completed; cancelled = voided before use; superseded = replaced by a revised prescription.. Valid values are `draft|approved|uploaded|applied|cancelled|superseded`',
    `rate_unit` STRING COMMENT 'Unit of measure for all prescribed application rates in this VRA prescription (e.g., lbs/acre for fertilizer, seeds/acre for seed, gal/acre for liquid crop protection). Standardizes rate comparisons across zones and seasons. [ENUM-REF-CANDIDATE: lbs/acre|gal/acre|oz/acre|seeds/acre|kg/ha|L/ha|bu/acre|tons/acre — 8 candidates stripped; promote to reference product]',
    `rei_hours` STRING COMMENT 'Restricted Entry Interval (REI) in hours as specified on the input product label, indicating the minimum time workers must stay out of treated areas after application. Required for OSHA and EPA worker protection standard compliance.',
    `source_system` STRING COMMENT 'Originating system from which this VRA prescription was created or imported. Enables data lineage tracking and system-of-record reconciliation across Trimble Ag Software, Climate FieldView, and John Deere Operations Center.. Valid values are `trimble_ag|climate_fieldview|john_deere_ops|granular|manual`',
    `source_system_reference` STRING COMMENT 'Native identifier of this VRA prescription record in the originating source system (Trimble Ag Software, Climate FieldView, or John Deere Operations Center). Enables bidirectional traceability between the lakehouse silver layer and operational systems.',
    `target_application_end_date` DATE COMMENT 'Latest date within the agronomically recommended application window for this VRA prescription. Prescriptions applied after this date may be flagged for agronomic review and compliance documentation.',
    `target_application_start_date` DATE COMMENT 'Earliest date within the agronomically recommended application window for this VRA prescription. Used for field scheduling, equipment dispatch planning, and PHI/REI compliance verification.',
    `total_field_area_acres` DECIMAL(18,2) COMMENT 'Total area of the field covered by this VRA prescription, measured in acres. Used to calculate total input quantity required, procurement planning, and cost-per-acre analysis.',
    `total_input_quantity` DECIMAL(18,2) COMMENT 'Total quantity of the agricultural input required to execute this VRA prescription across all zones, expressed in rate_unit denominator (e.g., total lbs, total gallons). Used for procurement planning, inventory reservation, and input cost estimation.',
    `updated_timestamp` TIMESTAMP COMMENT 'Date and time when this VRA prescription record was most recently modified. Tracks revisions to rates, zone assignments, or application windows after initial creation.',
    `version_number` STRING COMMENT 'Sequential version number of this VRA prescription, incremented each time the prescription is revised and re-approved. Enables version history tracking and ensures equipment operators apply the most current prescription.',
    `zone_count` STRING COMMENT 'Number of distinct management zones defined within this VRA prescription. Indicates the spatial complexity of the prescription and correlates with the degree of input variability across the field.',
    CONSTRAINT pk_vra_prescription PRIMARY KEY(`vra_prescription_id`)
) COMMENT 'Variable Rate Application (VRA) prescription map generated for a specific field and input type (seed, fertilizer, or crop protection), defining spatially variable application rates across field management zones. Captures prescription creation date, agronomist author, input product, rate units, zone map reference, target application window, and upload status to equipment controller (RTK-enabled). Links to source data (soil sampling results, scouting observations, yield history) that informed zone delineation. Post-application, actual vs. prescribed rate variance is reconciled through linked fertilization_event or protection_event records. Sourced from Trimble Ag Software and Climate FieldView. Enables precision agriculture, input cost optimization, and environmental compliance documentation.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`yield_record` (
    `yield_record_id` BIGINT COMMENT 'Unique system-generated surrogate identifier for each yield record entry representing a single harvest pass or harvest event at the field-season-variety level.',
    `asset_id` BIGINT COMMENT 'Reference to the combine harvester or harvest equipment unit used for this harvest pass. Sourced from John Deere Operations Center fleet telematics.',
    `certificate_of_analysis_id` BIGINT COMMENT 'Foreign key linking to quality.certificate_of_analysis. Business justification: Harvested commodity lots require a COA documenting pesticide residues, mycotoxins, moisture, and MRL compliance before sale to grain buyers or food manufacturers. Grain traceability and food safety co',
    `commodity_hedge_id` BIGINT COMMENT 'Foreign key linking to finance.commodity_hedge. Business justification: Harvested yield quantities are used to settle commodity hedge positions and test hedge effectiveness under ASC 815/IFRS 9. Finance teams link actual production records to hedge instruments to calculat',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Yield records are the primary source for commodity-level production reporting, USDA FSA/RMA submissions, and grain marketing. commodity_id normalizes the denormalized crop_type string and enables join',
    `crop_enterprise_budget_id` BIGINT COMMENT 'Foreign key linking to finance.crop_enterprise_budget. Business justification: Actual yield records are compared against enterprise budget planned yields and revenues for farm profitability variance analysis — a mandatory farm management report. Agronomists and controllers use t',
    `drought_index_id` BIGINT COMMENT 'Foreign key linking to weather.drought_index. Business justification: Yield loss attribution to drought is a core crop insurance (RMA indemnity) and agronomic reporting process. Linking yield_record to the drought_index record for the season/field supports yield varianc',
    `employee_id` BIGINT COMMENT 'Reference to the equipment operator or farm worker who conducted the harvest operation. Links to the Workforce domain for labor tracking and compliance.',
    `field_crop_plan_id` BIGINT COMMENT 'Reference to the crop plan that governed this field-season production cycle. Used to compute variance between planned yield targets and actual harvested yield.',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field where the harvest operation was performed. Links to the field master record in the Land and Soil domain.',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: Grain quality grading at harvest references a specific USDA grading standard that determines price discounts/premiums, elevator acceptance, and export eligibility. grading_standard_id normalizes the d',
    `growing_season_id` BIGINT COMMENT 'Reference to the crop production season (e.g., Spring 2024, Fall 2024) under which this harvest record is captured. Enables season-level rollup reporting.',
    `management_zone_id` BIGINT COMMENT 'Foreign key linking to land.management_zone. Business justification: Yield mapping by management zone is a core precision agriculture practice. Zone-level yield performance vs. soil productivity class drives future VRA prescription adjustments and zone-level ROI analys',
    `organic_certification_id` BIGINT COMMENT 'Foreign key linking to product.organic_certification. Business justification: Organic yield records must be traceable to the specific NOP certification for organic handler sales, premium pricing documentation, and NOP audit compliance. The yield record is the point of transfer ',
    `seed_variety_id` BIGINT COMMENT 'Reference to the specific crop variety or hybrid planted and harvested in this record. Enables variety-level yield benchmarking and seed performance analytics.',
    `storage_location_id` BIGINT COMMENT 'Reference to the grain bin, elevator, or storage facility where this harvested lot was delivered. Links to the Inventory domain for grain inventory management and WMS integration with Manhattan Associates.',
    `aph_yield_bu_per_acre` DECIMAL(18,2) COMMENT 'Actual Production History (APH) yield in bushels per acre as reported to USDA RMA for crop insurance purposes. May differ from yield_per_acre due to RMA-specific calculation rules (e.g., prevented planting adjustments, yield substitutions).',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this yield record was first created in the data platform. Used for audit trail, data lineage, and Silver layer ingestion tracking.',
    `crop_insurance_policy_number` STRING COMMENT 'USDA Risk Management Agency (RMA) crop insurance policy number associated with this field-season production. Required for Actual Production History (APH) documentation and indemnity claim filing under USDA RMA programs.',
    `damaged_kernels_pct` DECIMAL(18,2) COMMENT 'Percentage of heat-damaged, mold-damaged, or otherwise damaged kernels in the harvested grain sample. USDA grading factor impacting grade and market value. Elevated damage may indicate storage or disease issues requiring agronomic investigation.',
    `foreign_material_pct` DECIMAL(18,2) COMMENT 'Percentage of foreign material (weed seeds, chaff, dirt, other crop) in the harvested grain sample. USDA grading factor that affects grade assignment and may result in elevator dockage charges.',
    `gmo_status` STRING COMMENT 'GMO identity status of the harvested crop. Determines segregation requirements, storage bin assignment, and market channel eligibility. Critical for COOL (Country of Origin Labeling), export documentation, and identity-preserved grain premiums.. Valid values are `gmo|non_gmo|identity_preserved|organic`',
    `harvest_date` DATE COMMENT 'Calendar date on which the harvest operation was performed. Principal business event date for this transaction. Used for PHI compliance verification, crop insurance documentation, and agronomic reporting.',
    `harvest_end_timestamp` TIMESTAMP COMMENT 'Precise date and time when the harvest pass was completed on the field. Combined with harvest_start_timestamp to compute harvest duration and equipment OEE metrics.',
    `harvest_loss_pct` DECIMAL(18,2) COMMENT 'Estimated percentage of harvestable crop lost during the harvest operation due to combine settings, lodging, or field conditions. Sourced from combine loss monitor data via John Deere Operations Center. Used for equipment calibration and GAP compliance reporting.',
    `harvest_method` STRING COMMENT 'Method or header type used for the harvest operation. Affects harvest efficiency, grain loss estimates, and equipment OEE reporting. Sourced from John Deere Operations Center equipment configuration data.. Valid values are `combine|stripper_header|corn_head|draper_header|manual`',
    `harvest_start_timestamp` TIMESTAMP COMMENT 'Precise date and time when the harvest pass began on the field. Sourced from John Deere Operations Center GPS telematics. Used for OEE calculation and equipment utilization reporting.',
    `harvest_status` STRING COMMENT 'Current lifecycle status of the yield record. draft indicates data is being captured; in_progress indicates active harvest pass; completed indicates finalized and reconciled; cancelled indicates voided record; pending_review indicates awaiting quality or agronomic sign-off.. Valid values are `draft|in_progress|completed|cancelled|pending_review`',
    `harvested_area_acres` DECIMAL(18,2) COMMENT 'GPS-tracked actual harvested area in acres for this harvest pass. May differ from planted area due to field boundaries, obstacles, or partial harvests. Sourced from John Deere Operations Center precision agriculture data. Used as denominator for yield per acre (YPM) calculations.',
    `moisture_adjusted_production_bu` DECIMAL(18,2) COMMENT 'Total production adjusted to standard moisture basis in bushels. Calculated as: total_production_bu × ((100 - moisture_pct_at_harvest) / (100 - standard_moisture_pct)). Used for grain settlement, sales contract fulfillment, and financial crop enterprise accounting.',
    `moisture_pct_at_harvest` DECIMAL(18,2) COMMENT 'Grain moisture content percentage measured at the time of harvest (as-harvested moisture). Critical for drying cost calculation, storage decisions, and moisture-adjusted yield computation. Sourced from combine moisture sensor data via John Deere Operations Center.',
    `mrl_compliant` BOOLEAN COMMENT 'Indicates whether the harvested crop has been assessed as compliant with applicable Maximum Residue Limits (MRL) for pesticide residues per EPA, Codex Alimentarius, and destination market requirements. Required for export documentation and food safety compliance.',
    `ndvi_at_harvest` DECIMAL(18,2) COMMENT 'NDVI value recorded for the field at or near the harvest date. Ranges from -1 to +1; values above 0.6 indicate healthy dense canopy. Used to correlate remote sensing data with actual yield outcomes for predictive yield modeling and AI/ML applications.',
    `organic_certified` BOOLEAN COMMENT 'Indicates whether this harvest was produced under USDA National Organic Program (NOP) certified conditions. Drives premium pricing, segregation requirements, and organic certificate of analysis (COA) documentation.',
    `phi_compliance_verified` BOOLEAN COMMENT 'Indicates whether the Pre-Harvest Interval (PHI) for all applied crop protection products has been satisfied prior to this harvest date. Mandatory compliance check under EPA pesticide registration requirements and FSMA produce safety rules.',
    `source_system` STRING COMMENT 'Operational system of record from which this yield record was sourced. Enables data lineage tracking and reconciliation across John Deere Operations Center, Climate FieldView, Trimble Ag Software, and Granular Farm Management integrations.. Valid values are `john_deere_ops_center|climate_fieldview|trimble_ag|granular|manual_entry`',
    `standard_moisture_pct` DECIMAL(18,2) COMMENT 'Industry-standard moisture basis used for moisture-adjusted yield calculation (e.g., 15.5% for corn, 13% for soybeans). Defined by USDA grain grading standards and used as the reference point for dry bushel equivalents.',
    `test_weight_lbs_per_bu` DECIMAL(18,2) COMMENT 'Grain test weight measured in pounds per bushel (lbs/bu) at harvest. Key grain quality indicator used for USDA grade determination. Below-standard test weight may result in grade discounts at grain elevator. Sourced from combine sensors or grain elevator COA.',
    `total_production_bu` DECIMAL(18,2) COMMENT 'Total gross grain production in bushels (BU) recorded for this harvest pass at as-harvested moisture. Primary production quantity used for grain receipt (GRN) creation, sales contract fulfillment, and crop insurance documentation.',
    `total_production_mt` DECIMAL(18,2) COMMENT 'Total gross grain production converted to metric tons (MT) for international trade, export documentation, and financial reporting under IFRS. Derived from total_production_bu using commodity-specific conversion factors.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this yield record was last modified. Used for change data capture (CDC), audit trail, and data quality monitoring in the Databricks Silver layer.',
    `yield_per_acre` DECIMAL(18,2) COMMENT 'Actual harvested yield expressed as bushels per acre (BU/acre) for this harvest pass. Core agronomic performance metric (YPM) used for benchmarking against field crop plan targets, historical averages, and regional USDA NASS yield data.',
    `yield_target_bu_per_acre` DECIMAL(18,2) COMMENT 'Planned yield target in bushels per acre (BU/acre) from the associated crop plan for this field-season-variety combination. Used to compute yield variance and performance against plan for financial crop enterprise accounting.',
    `yield_variance_bu_per_acre` DECIMAL(18,2) COMMENT 'Difference between actual yield_per_acre and yield_target_bu_per_acre. Positive value indicates above-plan performance; negative value indicates shortfall. Used for financial crop enterprise accounting, crop insurance (USDA RMA APH), and agronomic benchmarking.',
    CONSTRAINT pk_yield_record PRIMARY KEY(`yield_record_id`)
) COMMENT 'Single source of truth for all yield and harvest performance data at the field-season-variety level. Captures individual harvest operation details: harvest date, combine/equipment used, operator, load ticket references, moisture content at harvest, test weight, grain quality grade, GPS-tracked harvest area, and field coverage. Aggregates production metrics: total production (BU, MT, CWT), average yield per acre (YPM), moisture-adjusted yield, quality grade distribution, and variance against the field crop plans yield target. Each harvest pass on a field is recorded as a yield_record entry, with season-level rollups computed for financial and agronomic reporting. Sourced from John Deere Operations Center and Climate FieldView harvest data. Serves as the authoritative yield SSOT for financial crop enterprise accounting, grain receipt (GRN) creation, sales contract fulfillment, crop insurance (USDA RMA) documentation, and agronomic benchmarking. Integrates with SAP S/4HANA PP and Granular Farm Management.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`rotation_plan` (
    `rotation_plan_id` BIGINT COMMENT 'Primary key for rotation_plan',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Long-term supply contracts in Agriculture often specify rotation requirements (organic transition, sustainability programs). Linking rotation_plan to the contracting buyer account supports multi-year ',
    `farm_unit_id` BIGINT COMMENT 'Reference to the farm or operational unit under which this rotation plan is managed, supporting multi-field farm-level rotation planning and NRCS compliance reporting.',
    `field_id` BIGINT COMMENT 'Reference to the specific field or farm unit for which this rotation plan is designed, linking to the land and soil domain field master record.',
    `growing_season_id` BIGINT COMMENT 'Reference to the current active growing season within this rotation plan, linking to the season master for calendar year and crop year alignment.',
    `employee_id` BIGINT COMMENT 'Reference to the certified agronomist or crop advisor responsible for designing and maintaining this rotation plan, used for GAP accountability and NRCS documentation.',
    `seed_variety_id` BIGINT COMMENT 'Reference to the crop variety planned for the second season/year of the rotation cycle. Supports multi-year rotation sequencing in Granular Farm Management.',
    `soil_profile_id` BIGINT COMMENT 'Foreign key linking to land.soil_profile. Business justification: Multi-year rotation plans are designed around soil profile characteristics (land capability class, drainage class, depth-to-restrictive-layer). NRCS conservation planning and CSP contracts require rot',
    `approved_date` DATE COMMENT 'Date on which this rotation plan was formally approved by the responsible agronomist or NRCS agent. Required for NRCS CSP contract initiation and GAP compliance audit trails.',
    `cover_crop_included` BOOLEAN COMMENT 'Indicates whether one or more cover crop phases are included in this rotation plan. True = cover crops are part of the rotation sequence; False = no cover crop phases planned. Relevant for NRCS CSP cover crop practice eligibility.',
    `cover_crop_species` STRING COMMENT 'Comma-separated list of cover crop species included in the rotation (e.g., Winter Rye, Hairy Vetch, Crimson Clover). Supports NRCS CSP practice documentation and soil health certification.',
    `cover_crop_termination_method` STRING COMMENT 'Method used to terminate cover crops prior to cash crop planting. Impacts soil disturbance, residue management, and organic certification compliance. [ENUM-REF-CANDIDATE: herbicide|tillage|roller_crimper|frost|mowing|grazing — promote to reference product if additional methods required]. Valid values are `herbicide|tillage|roller_crimper|frost|mowing`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this rotation plan record was first created in the system. Supports audit trail, data lineage, and NRCS CSP compliance documentation.',
    `csp_contract_number` STRING COMMENT 'USDA NRCS Conservation Stewardship Program (CSP) contract number linked to this rotation plan, enabling payment tracking and compliance verification for enrolled conservation practices.',
    `current_cycle_year` STRING COMMENT 'The current year position within the rotation cycle (e.g., 1, 2, or 3 for a 3-year rotation). Tracks where the field is in the rotation sequence for operational scheduling and compliance reporting.',
    `effective_end_date` DATE COMMENT 'The date on which this rotation plan expires or the final rotation cycle concludes. Nullable for open-ended plans. Used for NRCS CSP contract period management.',
    `effective_start_date` DATE COMMENT 'The date on which this rotation plan becomes binding and the first rotation cycle begins. Used for NRCS CSP compliance period tracking and Granular Farm Management scheduling.',
    `globalg_ap_certified` BOOLEAN COMMENT 'Indicates whether this rotation plan is aligned with GLOBALG.A.P. (Global Good Agricultural Practices) certification requirements for soil and crop management.',
    `gmo_trait_used` BOOLEAN COMMENT 'Indicates whether any crop variety in this rotation plan includes genetically modified organism (GMO) traits. True = GMO varieties included; False = non-GMO rotation. Required for COOL and export compliance documentation.',
    `last_reviewed_date` DATE COMMENT 'Date of the most recent agronomic review of this rotation plan. Annual reviews are required for NRCS CSP compliance and GLOBALG.A.P. certification maintenance.',
    `nitrogen_credit_lbs_acre` DECIMAL(18,2) COMMENT 'Estimated nitrogen (N) credit in pounds per acre attributed to legume phases or cover crops in the rotation, reducing synthetic nitrogen (NPK) fertilizer requirements for subsequent cash crops.',
    `notes` STRING COMMENT 'Free-text agronomic rationale, special instructions, or compliance notes for this rotation plan. Captures context such as pest pressure history, soil remediation objectives, or NRCS agent recommendations.',
    `nrcs_practice_code` STRING COMMENT 'USDA Natural Resources Conservation Service (NRCS) conservation practice standard code associated with this rotation plan (e.g., 328 for Conservation Crop Rotation). Required for CSP and EQIP payment eligibility documentation.',
    `organic_certified` BOOLEAN COMMENT 'Indicates whether this rotation plan is designed to meet USDA National Organic Program (NOP) certification requirements. True = organic-compliant rotation; False = conventional rotation.',
    `plan_name` STRING COMMENT 'Descriptive human-readable name for the rotation plan (e.g., Corn-Soybean-Wheat 3-Year Rotation - North Fields), used for identification in Granular Farm Management and agronomist reporting.',
    `plan_number` STRING COMMENT 'Externally-known, human-readable business identifier for the rotation plan, used in agronomist communications, NRCS documentation, and Granular Farm Management records. Format: ROT-{YYYY}-{NNNNNN}.. Valid values are `^ROT-[0-9]{4}-[0-9]{6}$`',
    `plan_status` STRING COMMENT 'Current lifecycle state of the rotation plan. draft = under development; active = currently being executed; suspended = temporarily paused; completed = all rotation cycles finished; cancelled = plan abandoned.. Valid values are `draft|active|suspended|completed|cancelled`',
    `plan_version` STRING COMMENT 'Version number of the rotation plan, incremented each time the plan is revised. Supports audit trail and change management for NRCS and GAP compliance documentation.',
    `planned_area_acres` DECIMAL(18,2) COMMENT 'Total field area in acres covered by this rotation plan. Used for input planning (seed, fertilizer, chemical), yield target setting, and NRCS CSP payment calculation.',
    `primary_agronomic_goal` STRING COMMENT 'The principal agronomic objective driving this rotation plan design (e.g., Soil organic matter improvement, Soybean cyst nematode suppression, Nitrogen fixation via legume phase, Weed resistance management). Supports NRCS CSP documentation and GAP rationale.',
    `rotation_cycle_years` STRING COMMENT 'Total number of years in one complete rotation cycle (e.g., 2 for corn-soybean, 3 for corn-soybean-wheat). Defines the repeating sequence length for soil health and pest cycle management.',
    `rotation_type` STRING COMMENT 'Classification of the rotation plan type. simple = two-crop alternation; complex = three or more crops; cover_crop = includes dedicated cover crop phases; organic = certified organic rotation; conventional = standard agrochemical-supported rotation.. Valid values are `simple|complex|cover_crop|organic|conventional`',
    `soil_health_score` DECIMAL(18,2) COMMENT 'Baseline composite soil health score for the field at the time of plan creation, derived from soil organic matter (OM), biological activity, and physical structure assessments. Supports NRCS CSP soil health practice documentation.',
    `soil_om_pct` DECIMAL(18,2) COMMENT 'Baseline soil organic matter (OM) percentage at plan initiation, expressed as a percentage of dry soil weight. Key indicator for rotation plan design and NRCS CSP soil health improvement targets.',
    `target_om_pct` DECIMAL(18,2) COMMENT 'Target soil organic matter (OM) percentage to be achieved by the end of the rotation plan period. Defines the agronomic improvement goal and supports NRCS CSP outcome measurement.',
    `tillage_system` STRING COMMENT 'Tillage system applied across this rotation plan, governing soil disturbance practices. Influences soil organic matter (OM) accumulation, erosion risk, and NRCS conservation compliance scoring.. Valid values are `conventional|reduced_till|no_till|strip_till`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this rotation plan record was last modified. Supports change management, version control, and NRCS CSP audit trail requirements.',
    CONSTRAINT pk_rotation_plan PRIMARY KEY(`rotation_plan_id`)
) COMMENT 'Multi-year crop rotation plan for a field or farm unit, defining the planned sequence of crops and cover crops across growing seasons to optimize soil health, break pest and disease cycles, manage nutrient cycling, and support conservation compliance. Captures rotation cycle length (years), crop sequence by season, cover crop species and termination timing, tillage system transitions, and agronomic rationale for each rotation choice. Supports NRCS Conservation Stewardship Program (CSP) documentation, GAP soil health certification, and long-term land productivity management within Granular Farm Management.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`loss_event` (
    `loss_event_id` BIGINT COMMENT 'Primary key for loss_event',
    `alert_id` BIGINT COMMENT 'Foreign key linking to weather.weather_alert. Business justification: Crop loss events are triggered by weather alerts (frost, hail, high wind). Linking loss_event to weather_alert supports RMA/USDA insurance claim filing, adjuster verification, and disaster reporting. ',
    `account_id` BIGINT COMMENT 'Foreign key linking to customer.account. Business justification: Supply contract management: crop loss events (weather, pest, disease) trigger force majeure notifications and supply shortfall alerts to contracted buyers. Linking loss_event to the buyer account enab',
    `employee_id` BIGINT COMMENT 'Reference to the licensed crop insurance loss adjuster assigned to assess and document the loss event for USDA RMA claim processing.',
    `fault_id` BIGINT COMMENT 'Foreign key linking to equipment.equipment_fault. Business justification: Crop losses caused by equipment failures (combine fire, planter skip, sprayer malfunction) must link to the causative equipment fault for insurance claim documentation, root cause analysis, and warran',
    `field_crop_plan_id` BIGINT COMMENT 'Reference to the active crop plan for the affected field and season, linking the loss event to the planned agronomic program, yield targets, and crop variety.',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field where the crop loss event occurred. Links to the field master record for geospatial and agronomic context.',
    `frost_alert_id` BIGINT COMMENT 'Foreign key linking to weather.frost_alert. Business justification: Frost is a primary crop loss cause with dedicated RMA insurance reporting requirements. Linking loss_event directly to frost_alert supports frost-specific indemnity claims, adjuster documentation, and',
    `government_program_id` BIGINT COMMENT 'Foreign key linking to finance.government_program. Business justification: Crop loss events trigger USDA government program claims (NAP, WHIP+, crop insurance indemnity). The loss_event carries insurance_policy_number as a denormalized attribute; a proper FK to government_pr',
    `growing_season_id` BIGINT COMMENT 'Reference to the crop production season (e.g., Spring 2024, Fall 2024) during which the loss event occurred. Used for seasonal aggregation and insurance policy alignment.',
    `herd_id` BIGINT COMMENT 'Foreign key linking to livestock.herd. Business justification: Crop damage attribution: crop loss events caused by livestock (fence failure, overgrazing, trespass) require identifying the responsible herd for crop insurance claims, internal liability reporting, a',
    `nonconformance_id` BIGINT COMMENT 'Foreign key linking to quality.nonconformance. Business justification: Crop loss events caused by mycotoxin contamination, pesticide drift, or food safety hazards generate quality nonconformances. Linking loss_event to nonconformance supports insurance claim documentatio',
    `precipitation_event_id` BIGINT COMMENT 'Foreign key linking to weather.precipitation_event. Business justification: Hail, flooding, and storm events are primary crop loss causes requiring USDA disaster reporting and insurance claim substantiation. Linking loss_event to precipitation_event provides the documented we',
    `contract_id` BIGINT COMMENT 'Foreign key linking to sales.contract. Business justification: Force majeure and contract renegotiation: when a crop loss event occurs, the affected sales contracts must be identified immediately for renegotiation or force majeure invocation. Every grain merchand',
    `seed_variety_id` BIGINT COMMENT 'Reference to the specific crop variety affected by the loss event. Supports variety-level loss analysis and insurance claim documentation.',
    `yield_record_id` BIGINT COMMENT 'Foreign key linking to crop.yield_record. Business justification: loss_event has no FK to yield_record, yet crop loss events directly impact the yield outcomes captured in yield_record. Adding yield_record_id to loss_event enables direct linkage between documented l',
    `adjuster_inspection_date` DATE COMMENT 'The date on which the licensed crop insurance adjuster conducted the field inspection to assess the loss event. Required for USDA RMA claim documentation and loss adjustment timeline compliance.',
    `adjuster_reference_number` STRING COMMENT 'The adjusters internal reference or case number assigned during the field inspection and loss assessment process. Used for cross-referencing adjuster reports with the insurance claim file.',
    `affected_area_acres` DECIMAL(18,2) COMMENT 'Total acreage of the field or portion thereof affected by the crop loss event, measured in acres. Used for indemnity calculation and USDA RMA claim documentation. Aligns with FSA CLU (Common Land Unit) acreage records.',
    `assessment_method` STRING COMMENT 'Method used to assess and quantify the crop loss or damage. Determines the evidentiary basis for the insurance claim and agronomic documentation. [ENUM-REF-CANDIDATE: visual_inspection|drone_survey|adjuster_inspection|satellite_imagery|yield_monitor|lab_sample — promote to reference product]. Valid values are `visual_inspection|drone_survey|adjuster_inspection|satellite_imagery|yield_monitor|lab_sample`',
    `created_timestamp` TIMESTAMP COMMENT 'The timestamp when the crop loss event record was first created in the system. Audit trail field for data lineage, SOX compliance, and FSMA record-keeping requirements.',
    `crop_growth_stage` STRING COMMENT 'The phenological growth stage of the crop at the time of the loss event (e.g., V6, R3 for corn; Feekes 10.5 for wheat). Critical for determining yield impact severity and insurance coverage applicability under MPCI policy.',
    `estimated_indemnity_usd` DECIMAL(18,2) COMMENT 'The estimated indemnity payment amount in US dollars calculated based on the assessed yield loss, insured price, and policy coverage level. Preliminary figure prior to final indemnity determination.',
    `event_number` STRING COMMENT 'Externally-known business identifier for the crop loss event, used in communications with insurers, adjusters, and USDA RMA. Typically assigned by the farm management or ERP system (e.g., SAP S/4HANA QM module).',
    `event_status` STRING COMMENT 'Current lifecycle status of the crop loss event from initial reporting through final indemnity determination. [ENUM-REF-CANDIDATE: reported|under_review|adjuster_assigned|assessed|claim_filed|settled|closed|denied — promote to reference product]',
    `expected_yield_bu_acre` DECIMAL(18,2) COMMENT 'The approved actual production history (APH) or expected yield in bushels per acre for the insured unit at the time of the loss event. Baseline for indemnity calculation under MPCI policy.',
    `final_indemnity_usd` DECIMAL(18,2) COMMENT 'The final approved indemnity payment amount in US dollars as determined by the approved insurance provider (AIP) and USDA RMA following completion of the loss adjustment process. Used for financial loss reporting and SAP FI/CO posting.',
    `gis_polygon_reference` STRING COMMENT 'Reference identifier for the GIS polygon or spatial feature in Esri ArcGIS representing the precise geographic boundary of the affected area within the field. Enables spatial analysis and precision agriculture integration.',
    `indemnity_determination_date` DATE COMMENT 'The date on which the final indemnity amount was officially determined and approved by the insurance provider and USDA RMA. Triggers financial posting in SAP FI and revenue recognition under GAAP/IFRS.',
    `insurance_claim_number` STRING COMMENT 'The unique claim number assigned by the approved insurance provider (AIP) or USDA RMA upon formal submission of the loss event claim. Used for claim tracking and ADM system integration.',
    `loss_cause` STRING COMMENT 'Primary cause or peril responsible for the crop loss or damage event. Determines applicable insurance coverage type and USDA RMA cause-of-loss code. [ENUM-REF-CANDIDATE: hail|drought|flood|frost|pest|disease|wind|fire|excess_moisture|prevented_planting — promote to reference product]',
    `loss_cause_detail` STRING COMMENT 'Detailed narrative description of the specific cause of loss, providing additional context beyond the primary cause code (e.g., Late-season frost event on 2024-04-15, temperatures dropped to -3°C for 4 hours). Supports adjuster documentation and RMA claim narrative.',
    `loss_date` DATE COMMENT 'The calendar date on which the crop loss or damage event occurred or was first observed. This is the principal real-world event date used for insurance claim eligibility and PHI/REI compliance verification.',
    `loss_description` STRING COMMENT 'Full narrative description of the crop loss event including observed damage symptoms, affected crop growth stage, and initial field conditions. Used for agronomic risk management and insurance documentation.',
    `loss_severity` STRING COMMENT 'Categorical severity classification of the crop loss event based on the assessed yield loss percentage. Used for prioritization of adjuster resources, financial risk reporting, and agronomic risk management KPI tracking.. Valid values are `minor|moderate|severe|total_loss`',
    `ndvi_at_loss` DECIMAL(18,2) COMMENT 'NDVI value recorded for the affected field area at or near the time of the loss event, derived from satellite or drone imagery. Provides objective remote-sensing evidence of crop health degradation for insurance and agronomic documentation.',
    `notes` STRING COMMENT 'Free-text field for additional operational notes, adjuster comments, or agronomic observations related to the loss event that do not fit structured fields. Supports comprehensive documentation for insurance and compliance purposes.',
    `phi_compliant` BOOLEAN COMMENT 'Indicates whether the crop loss event and any associated pesticide applications were compliant with the Pre-Harvest Interval (PHI) requirements at the time of loss. Critical for food safety and MRL compliance documentation under FSMA and EPA regulations.',
    `policy_coverage_type` STRING COMMENT 'Type of crop insurance policy coverage applicable to this loss event. Determines the indemnity calculation methodology and USDA RMA reporting requirements.. Valid values are `MPCI|crop_hail|revenue_protection|yield_protection|whole_farm`',
    `prevented_planting_flag` BOOLEAN COMMENT 'Indicates whether the loss event qualifies as a prevented planting claim under USDA RMA MPCI policy, where the insured was unable to plant the insured crop by the final planting date due to an insured cause of loss.',
    `replanting_recommended` BOOLEAN COMMENT 'Indicates whether the agronomist or loss adjuster has recommended replanting of the affected area following the loss event. Triggers replanting payment eligibility assessment under MPCI policy.',
    `reported_date` DATE COMMENT 'The date on which the crop loss event was formally reported to the crop insurance agent or USDA RMA. Critical for claim filing deadline compliance under MPCI policy terms.',
    `rma_adm_submission_date` DATE COMMENT 'The date on which the loss event claim data was electronically submitted to the USDA Risk Management Agency (RMA) Actuarial Data Master (ADM) system for official claim processing and reinsurance reporting.',
    `total_field_acres` DECIMAL(18,2) COMMENT 'Total insured acreage of the field at the time of the loss event. Used to calculate the percentage of field affected and to validate affected_area_acres against the insured unit.',
    `updated_timestamp` TIMESTAMP COMMENT 'The timestamp when the crop loss event record was last modified. Supports audit trail, data lineage tracking, and change management for insurance claim documentation.',
    `yield_loss_bu_acre` DECIMAL(18,2) COMMENT 'Estimated yield loss expressed in bushels per acre (BU/acre) resulting from the crop loss event. Primary quantitative metric for MPCI indemnity calculation and agronomic impact assessment. Aligns with YPM reporting standards.',
    `yield_loss_pct` DECIMAL(18,2) COMMENT 'Estimated yield loss expressed as a percentage of the expected yield for the affected area. Used for crop-hail policy claims and comparative loss analysis across fields and seasons.',
    CONSTRAINT pk_loss_event PRIMARY KEY(`loss_event_id`)
) COMMENT 'Record of a crop loss or damage event affecting a field or portion thereof, capturing loss date, cause (hail, drought, flood, frost, pest, disease, wind), estimated yield impact (BU/acre or % loss), affected acreage, loss assessment method (visual, drone survey, adjuster inspection), adjuster reference, crop insurance claim number, policy reference, and final indemnity determination. May be triggered by scouting observations identifying severe damage or by weather event alerts. Supports crop insurance (USDA RMA) claim processing, MPCI and crop-hail policy documentation, financial loss reporting, and agronomic risk management. Integrates with USDA RMA ADM system for electronic claim submission.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`cover_crop` (
    `cover_crop_id` BIGINT COMMENT 'Unique system-generated identifier for the cover crop planting record. Primary key for the cover_crop entity.',
    `asset_id` BIGINT COMMENT 'Reference to the planting or seeding equipment used to establish the cover crop. Supports equipment utilization tracking, calibration records, and field operation cost allocation.',
    `equipment_field_operation_id` BIGINT COMMENT 'Foreign key linking to equipment.field_operation. Business justification: Cover crop planting and termination are executed as field operations. Linking enables equipment utilization tracking for cover crop activities, NRCS practice implementation documentation, and CSP paym',
    `field_crop_plan_id` BIGINT COMMENT 'Foreign key linking to crop.field_crop_plan. Business justification: cover_crop links to rotation_plan and growing_season but has no FK to field_crop_plan. Cover crop plantings are integral to the field-level agronomic plan — the field_crop_plans organic_certified and',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field on which this cover crop was planted. Links to the land and soil domain field master record.',
    `herd_id` BIGINT COMMENT 'Foreign key linking to livestock.herd. Business justification: Cover crop grazing management: in integrated crop-livestock operations, cover crops are commonly terminated by grazing. Tracking which herd grazed the cover crop is required for herd nutrition records',
    `growing_season_id` BIGINT COMMENT 'Reference to the growing season during which this cover crop planting is associated. Typically the off-season or inter-season period between primary cash crop seasons.',
    `organic_certification_id` BIGINT COMMENT 'Foreign key linking to product.organic_certification. Business justification: Cover crops in certified organic systems must use organically produced seed and approved practices. organic_certification_id links the cover crop record to the NOP certification covering the field ope',
    `employee_id` BIGINT COMMENT 'Reference to the agronomist or crop advisor responsible for prescribing and overseeing this cover crop planting program.',
    `rotation_plan_id` BIGINT COMMENT 'Reference to the crop rotation plan that prescribes this cover crop planting as part of a multi-season soil health or conservation strategy.',
    `seed_lot_id` BIGINT COMMENT 'Reference to the seed lot used for this cover crop planting. Enables traceability from field planting back to seed origin, certification class, germination test results, and supplier.',
    `station_id` BIGINT COMMENT 'Reference to the weather station providing meteorological data (temperature, precipitation, ET) for this cover crop planting location. Supports growing degree day calculations and irrigation scheduling.',
    `work_order_id` BIGINT COMMENT 'Foreign key linking to equipment.work_order. Business justification: Cover crop planting and termination operations require work orders for equipment scheduling and cost tracking. NRCS/CSP practice payment documentation requires linking cover crop field activities to a',
    `parent_cover_crop_id` BIGINT COMMENT 'Self-referencing FK on cover_crop (parent_cover_crop_id)',
    `biomass_estimate_lbs_acre` DECIMAL(18,2) COMMENT 'Estimated above-ground dry biomass produced by the cover crop at termination, expressed in pounds per acre. Key indicator of soil organic matter contribution, nitrogen cycling potential, and weed suppression effectiveness.',
    `cover_crop_type` STRING COMMENT 'Functional classification of the cover crop by plant family or agronomic category. Determines nitrogen fixation potential, biomass contribution, and soil health benefit. mix indicates a multi-species blend.. Valid values are `grass|legume|brassica|broadleaf|mix`',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this cover crop planting record was first created in the system. Supports audit trail, data lineage, and record provenance tracking in the Databricks Silver Layer.',
    `csp_contract_number` STRING COMMENT 'USDA Conservation Stewardship Program contract number under which this cover crop planting qualifies for conservation payment. Links field-level practice to federal program financial records.',
    `days_to_termination` STRING COMMENT 'Number of calendar days between the cover crop planting date and the actual termination date. Indicates the length of the cover crop growing window and is used to assess biomass accumulation potential and program compliance.',
    `establishment_rating` STRING COMMENT 'Field-assessed qualitative rating of cover crop stand establishment success. Evaluated by agronomist or field scout based on germination uniformity, plant density, and canopy coverage. Informs replanting decisions.. Valid values are `excellent|good|fair|poor|failed`',
    `fsma_compliant` BOOLEAN COMMENT 'Indicates whether the cover crop termination timing and method comply with FSMA Produce Safety Rule requirements for application of biological soil amendments. Particularly relevant for fields transitioning to fresh produce crops.',
    `gps_coverage_geojson` STRING COMMENT 'GeoJSON polygon representing the GPS-mapped boundary of the actual cover crop planted area within the field. Supports precision agriculture spatial analysis, as-applied mapping, and NRCS program acreage verification.',
    `is_bmp_compliant` BOOLEAN COMMENT 'Indicates whether this cover crop planting meets applicable Best Management Practices (BMP) for water quality, nutrient management, and erosion control as defined by state or federal environmental agencies.',
    `ndvi_at_termination` DECIMAL(18,2) COMMENT 'NDVI (Normalized Difference Vegetation Index) value measured at or near the cover crop termination date. Provides an objective, remote-sensing-based indicator of cover crop biomass and canopy health at termination.',
    `nitrogen_credit_lbs_acre` DECIMAL(18,2) COMMENT 'Estimated plant-available nitrogen credit in pounds per acre attributed to legume cover crop nitrogen fixation or biomass decomposition. Used to adjust NPK fertilizer application rates for the subsequent cash crop season.',
    `notes` STRING COMMENT 'Free-text field for agronomist or operator observations regarding this cover crop planting, including establishment challenges, weather impacts, pest pressure, or special management actions taken.',
    `nrcs_practice_code` STRING COMMENT 'USDA Natural Resources Conservation Service conservation practice standard code associated with this cover crop planting (e.g., 340 for Cover Crop). Required for EQIP, CSP, and other USDA conservation program payment documentation.',
    `organic_certified` BOOLEAN COMMENT 'Indicates whether this cover crop planting is conducted under a certified organic production system in compliance with USDA National Organic Program (NOP) standards. Affects allowable termination methods and input restrictions.',
    `planned_planting_date` DATE COMMENT 'Originally scheduled planting date for the cover crop as defined in the rotation plan or agronomic prescription. Enables variance analysis between planned and actual planting timing.',
    `planted_area_acres` DECIMAL(18,2) COMMENT 'Total area in acres on which the cover crop was successfully planted. Used for seed cost accounting, NRCS program payment calculations, and soil health program reporting.',
    `planting_date` DATE COMMENT 'Actual calendar date on which the cover crop seed was planted or broadcast in the field. Used for growing degree day (GDD) accumulation tracking, establishment assessment, and program compliance verification.',
    `planting_method` STRING COMMENT 'Method used to establish the cover crop. Affects seed-to-soil contact, establishment success rate, and seeding rate requirements. interseeding refers to planting into a standing cash crop canopy.. Valid values are `drill|broadcast|aerial|interseeding|overseeding`',
    `planting_status` STRING COMMENT 'Current lifecycle status of the cover crop planting record. Tracks progression from planning through establishment and termination. failed indicates the cover crop did not establish adequately.. Valid values are `planned|planted|established|terminated|failed`',
    `prescribed_seeding_rate_lbs_acre` DECIMAL(18,2) COMMENT 'Agronomist-prescribed target seeding rate in pounds per acre as specified in the cover crop prescription or rotation plan. Enables variance analysis against actual seeding rate applied.',
    `primary_goal` STRING COMMENT 'Primary agronomic or conservation objective for planting this cover crop. Drives species selection, seeding rate, and termination timing decisions. Used in NRCS program reporting and CSP payment calculations.. Valid values are `nitrogen_fixation|erosion_control|weed_suppression|soil_health|compaction_relief|water_quality`',
    `record_number` STRING COMMENT 'Human-readable, externally referenceable business identifier for this cover crop planting record. Used in field documentation, NRCS program submissions, and CSP contract reporting. Format: CC-{YEAR}-{SEQUENCE}.. Valid values are `^CC-[0-9]{4}-[0-9]{6}$`',
    `seed_cost_usd` DECIMAL(18,2) COMMENT 'Total seed cost in US dollars for this cover crop planting, calculated from seed lot unit cost and quantity used. Used in enterprise budget tracking, NRCS program cost-share calculations, and crop enterprise profitability analysis.',
    `seeding_rate_lbs_acre` DECIMAL(18,2) COMMENT 'Actual seeding rate applied for the cover crop, expressed in pounds of seed per acre. Used to verify compliance with NRCS practice standards, calculate seed costs, and assess establishment adequacy.',
    `soil_cover_pct` DECIMAL(18,2) COMMENT 'Estimated percentage of soil surface covered by the cover crop canopy or residue at peak growth or at termination. Key metric for erosion control effectiveness and NRCS practice standard compliance verification.',
    `soil_temperature_at_planting_c` DECIMAL(18,2) COMMENT 'Soil temperature in degrees Celsius measured at the time of cover crop planting. Critical for predicting germination success and establishment timing, particularly for cool-season cover crop species.',
    `source_system` STRING COMMENT 'Operational system of record from which this cover crop planting record originated. Supports data lineage, integration audit trails, and conflict resolution in the FMIS data lakehouse.. Valid values are `Climate_FieldView|Trimble_Ag|Granular|John_Deere_Ops|SAP_S4HANA|Manual`',
    `species_mix_name` STRING COMMENT 'Common name or blend designation of the cover crop species or species mix planted (e.g., Winter Rye, Crimson Clover, Cereal Rye + Hairy Vetch Mix). Supports soil health program documentation and seed procurement.',
    `species_scientific_name` STRING COMMENT 'Botanical (scientific) name of the primary cover crop species or lead species in a mix (e.g., Secale cereale, Trifolium incarnatum). Required for NRCS program compliance and GLOBALG.A.P. documentation.',
    `termination_date` DATE COMMENT 'Actual date on which the cover crop was terminated (killed or incorporated). Critical for calculating days of cover, biomass accumulation, and ensuring adequate decomposition time before primary crop planting.',
    `termination_method` STRING COMMENT 'Method used to terminate (kill) the cover crop prior to primary crop planting. Affects residue management, soil disturbance, and organic certification compliance. roller_crimper is preferred in no-till and organic systems.. Valid values are `herbicide|tillage|roller_crimper|frost|mowing|incorporation`',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this cover crop planting record was last modified. Supports change tracking, data quality monitoring, and incremental ETL processing in the Databricks Lakehouse Silver Layer.',
    CONSTRAINT pk_cover_crop PRIMARY KEY(`cover_crop_id`)
) COMMENT 'Master record for cover crop plantings used in conservation and soil health programs between primary cash crop seasons. Captures cover crop species or mix, seeding rate, planting date, termination date and method, biomass estimate, and associated field and growing season references.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`harvest_event` (
    `harvest_event_id` BIGINT COMMENT 'Unique system-generated identifier for each harvest event record. Primary key for the harvest_event data product in the crop domain Silver layer.',
    `asset_id` BIGINT COMMENT 'Reference to the primary harvest equipment (e.g., combine harvester) used during this event. Supports equipment utilization, OEE tracking, and maintenance scheduling.',
    `commodity_id` BIGINT COMMENT 'Foreign key linking to product.commodity. Business justification: Harvest events are recorded against a specific commodity for grain elevator delivery, load ticket generation, and FSMA traceability. commodity_id normalizes the denormalized crop_type string and enabl',
    `commodity_lot_id` BIGINT COMMENT 'Foreign key linking to inventory.commodity_lot. Business justification: Each harvest event produces a commodity lot in inventory. This link supports harvest-to-inventory traceability for food safety audits, grain marketing, and FSMA compliance. grn_number on harvest_event',
    `crew_id` BIGINT COMMENT 'Foreign key linking to workforce.crew. Business justification: Harvest crew tracking: harvest operations are crew-based in large-scale agriculture. Linking harvest_event to crew enables piece-rate payroll calculation, H2A compliance verification during harvest, a',
    `employee_id` BIGINT COMMENT 'Reference to the equipment operator or farm worker who executed the harvest operation. Used for workforce accountability, GAP compliance, and operator performance tracking.',
    `equipment_field_operation_id` BIGINT COMMENT 'Foreign key linking to equipment.field_operation. Business justification: Harvest events are the agronomic record; field_operation is the equipment execution record. Linking enables combine OEE analysis, fuel cost per bushel, and harvest efficiency benchmarking. Standard pr',
    `field_crop_plan_id` BIGINT COMMENT 'Reference to the field crop plan that governed the production cycle for this harvest event, linking agronomic planning to actual harvest execution.',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field on which this harvest event was executed. Links to the field master record in the land and soil domain.',
    `grading_standard_id` BIGINT COMMENT 'Foreign key linking to product.grading_standard. Business justification: Harvest quality grading at the event level references the applicable USDA grading standard for load ticket acceptance at grain elevators and price determination. grading_standard_id normalizes the den',
    `growing_season_id` BIGINT COMMENT 'Reference to the growing season during which this harvest event occurred, enabling season-level aggregation and year-over-year yield comparisons.',
    `inventory_goods_receipt_id` BIGINT COMMENT 'Foreign key linking to inventory.goods_receipt. Business justification: When harvested grain is delivered to storage, a goods receipt is created. Linking harvest_event to goods_receipt supports the farm-to-warehouse receiving process and enables reconciliation of harveste',
    `lab_sample_id` BIGINT COMMENT 'Foreign key linking to quality.lab_sample. Business justification: At harvest, lab samples are collected for pesticide residue, mycotoxin, and moisture testing. FSMA and GAP require traceability from the harvest event to the food safety lab sample. No existing FK or ',
    `contract_id` BIGINT COMMENT 'Foreign key linking to sales.contract. Business justification: Contract fulfillment at harvest: harvest events are applied against open sales contracts in grain merchandising. Linking harvest_event to the contract being fulfilled enables real-time contract positi',
    `seed_variety_id` BIGINT COMMENT 'Reference to the specific crop variety harvested during this event, supporting variety-level yield performance analysis and seed selection decisions.',
    `storage_location_id` BIGINT COMMENT 'Reference to the grain bin, elevator, or storage facility where harvested commodity was delivered. Supports inventory management, traceability, and WMS integration.',
    `observation_id` BIGINT COMMENT 'Foreign key linking to weather.observation. Business justification: Harvest events record weather_condition as denormalized text. Linking to the actual weather observation supports grain quality traceability (moisture, temperature at harvest), insurance documentation,',
    `weight_ticket_id` BIGINT COMMENT 'Foreign key linking to invoice.weight_ticket. Business justification: Grain delivery traceability: each harvest event (combine load) produces a weight ticket at point of delivery. This FK links the operational harvest record to the commercial scale ticket used for invoi',
    `yield_record_id` BIGINT COMMENT 'Reference to the final reconciled yield record associated with this harvest event. Establishes the link between the operational harvest transaction and the authoritative yield data.',
    `parent_harvest_event_id` BIGINT COMMENT 'Self-referencing FK on harvest_event (parent_harvest_event_id)',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this harvest event record was first created in the data platform. Used for audit trail, data lineage, and Silver layer ingestion tracking. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    `crop_growth_stage` STRING COMMENT 'BBCH or crop-specific growth stage code at the time of harvest (e.g., R6 for corn black layer, R8 for soybean full maturity). Indicates physiological maturity and harvest readiness.',
    `damaged_kernels_pct` DECIMAL(18,2) COMMENT 'Percentage of damaged, heat-damaged, or diseased kernels in the harvested grain sample. Impacts grain grade, price dockage, and storage risk assessment.',
    `event_number` STRING COMMENT 'Externally visible business identifier for this harvest event, used in operational communications, load tickets, and cross-system references (e.g., HRV-2024-00123). Sourced from SAP S/4HANA PP or John Deere Operations Center.',
    `event_status` STRING COMMENT 'Current lifecycle status of the harvest event, tracking progression from planning through execution to completion or cancellation.. Valid values are `planned|in_progress|completed|cancelled|on_hold`',
    `foreign_material_pct` DECIMAL(18,2) COMMENT 'Percentage of foreign material (non-grain matter) present in the harvested sample. Used for grain grading, dockage calculation, and quality compliance per USDA GIPSA standards.',
    `gps_coverage_geojson` STRING COMMENT 'GeoJSON polygon or multipolygon representing the actual GPS-tracked area covered during the harvest operation. Enables precision agriculture analysis, as-harvested mapping, and FSA acreage verification.',
    `gross_weight_bu` DECIMAL(18,2) COMMENT 'Total gross weight of harvested grain or commodity measured in bushels (BU) at the time of harvest, prior to moisture adjustment or dockage. Primary yield quantity metric for grain crops.',
    `gross_weight_mt` DECIMAL(18,2) COMMENT 'Total gross weight of harvested commodity in metric tons (MT), supporting international trade reporting, export documentation, and CIF/FOB calculations.',
    `harvest_date` DATE COMMENT 'Calendar date on which the harvest operation was performed. Used for PHI compliance verification, crop insurance reporting, and seasonal analytics. Format: yyyy-MM-dd.',
    `harvest_end_timestamp` TIMESTAMP COMMENT 'Precise date and time when the harvest operation was completed on the field. Combined with start timestamp to compute actual harvest duration for OEE and productivity analysis.',
    `harvest_loss_pct` DECIMAL(18,2) COMMENT 'Estimated percentage of harvestable yield lost during the harvest operation due to equipment settings, crop conditions, or field factors. Used for equipment calibration and operational efficiency improvement.',
    `harvest_method` STRING COMMENT 'Method or equipment type used to harvest the crop. Influences post-harvest handling procedures, grain quality outcomes, and harvest loss estimates.. Valid values are `combine|stripper_header|forage_harvester|manual|baler|other`',
    `harvest_start_timestamp` TIMESTAMP COMMENT 'Precise date and time when the harvest operation commenced on the field. Used for equipment utilization analysis, OEE calculation, and operator time tracking.',
    `harvested_area_acres` DECIMAL(18,2) COMMENT 'Total field area harvested during this event, measured in acres. Used for yield-per-acre calculations, crop insurance reporting, and FSA acreage certification.',
    `is_gmo` BOOLEAN COMMENT 'Indicates whether the harvested crop contains genetically modified organism (GMO) traits. Required for identity preservation, COOL labeling, export documentation, and USDA APHIS compliance.',
    `moisture_pct_at_harvest` DECIMAL(18,2) COMMENT 'Grain moisture content percentage measured at the time of harvest. Critical for determining drying requirements, storage eligibility, and moisture-adjusted yield calculations. Industry standard for corn is 15.5%, soybeans 13%.',
    `mrl_compliant` BOOLEAN COMMENT 'Indicates whether the harvested crop meets Maximum Residue Limit (MRL) requirements for pesticide residues as established by EPA, FDA, and applicable international standards (Codex Alimentarius).',
    `ndvi_at_harvest` DECIMAL(18,2) COMMENT 'NDVI value captured from satellite or drone imagery at or near the time of harvest. Used to correlate canopy health with final yield outcomes and validate remote sensing models.',
    `notes` STRING COMMENT 'Free-text field for operator or agronomist observations about the harvest event, including equipment issues, field conditions, crop anomalies, or other contextual information not captured in structured fields.',
    `organic_certified` BOOLEAN COMMENT 'Indicates whether the harvested crop was produced under USDA National Organic Program (NOP) certified conditions. Required for organic premium pricing, identity preservation, and NOP compliance documentation.',
    `phi_compliance_verified` BOOLEAN COMMENT 'Indicates whether the required Pre-Harvest Interval (PHI) for all applied crop protection products has been satisfied prior to this harvest event. Mandatory for food safety and MRL compliance under FSMA and EPA regulations.',
    `source_system` STRING COMMENT 'Operational system of record from which this harvest event data originated (e.g., John Deere Operations Center, Climate FieldView, SAP S/4HANA PP). Supports data lineage and SSOT governance.. Valid values are `SAP_S4HANA|JOHN_DEERE_OPS|CLIMATE_FIELDVIEW|TRIMBLE_AG|GRANULAR|MANUAL`',
    `source_system_event_reference` STRING COMMENT 'Native identifier of this harvest event in the originating operational system (e.g., John Deere Operations Center machine data ID, Climate FieldView harvest activity ID). Enables cross-system reconciliation and audit traceability.',
    `standard_moisture_pct` DECIMAL(18,2) COMMENT 'Industry-standard moisture percentage used as the basis for moisture-adjusted yield calculations and grain pricing (e.g., 15.5% for corn, 13.0% for soybeans per USDA GIPSA standards).',
    `test_weight_lbs_per_bu` DECIMAL(18,2) COMMENT 'Grain density measurement expressed as pounds per bushel (lbs/bu), indicating grain quality and maturity. Used for grade determination and price dockage calculations per USDA GIPSA standards.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this harvest event record was last modified in the data platform. Supports change tracking, data quality monitoring, and audit compliance. Format: yyyy-MM-ddTHH:mm:ss.SSSXXX.',
    CONSTRAINT pk_harvest_event PRIMARY KEY(`harvest_event_id`)
) COMMENT 'Transactional record of an actual harvest operation executed on a field, capturing harvest date, operator, equipment used, crop harvested, field area harvested, moisture at harvest, yield weight, and grain quality observations. Links to yield_record for final reconciled yield data.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`grain_delivery` (
    `grain_delivery_id` BIGINT COMMENT 'Primary key for the grain_delivery association',
    `delivery_location_id` BIGINT COMMENT 'Foreign key linking this grain delivery to the authorized customer receiving location where the grain was delivered.',
    `yield_record_id` BIGINT COMMENT 'Foreign key linking this grain delivery to the specific harvest yield record from which the delivered grain originated.',
    `allocated_quantity_mt` DECIMAL(18,2) COMMENT 'Quantity of grain from this yield record allocated and delivered to this specific delivery location, expressed in metric tons. Belongs to the delivery relationship — the same yield record may have different quantities allocated to different locations.',
    `cool_origin_verified` BOOLEAN COMMENT 'Indicates whether Country of Origin Labeling (COOL) compliance has been verified for this specific grain delivery. Required for food manufacturing and retail customers under USDA COOL regulations. Belongs to the delivery event as it is verified per shipment, not per yield record or per location.',
    `delivery_date` DATE COMMENT 'Calendar date on which the grain was physically delivered to and received at the delivery location. Belongs to the delivery event, not to the yield record (harvest date) or the delivery location (static master).',
    `load_ticket_number` STRING COMMENT 'Bill of Lading or scale ticket reference number issued at the time of this specific delivery. Uniquely identifies the physical load movement from the farm/storage to the receiving location. Belongs to the delivery event.',
    `moisture_at_delivery` DECIMAL(18,2) COMMENT 'Grain moisture content percentage as measured by the receiving location at the time of delivery. Used for moisture dockage calculations and settlement. Distinct from moisture_pct_at_harvest on the yield_record, which is measured at the field.',
    `quality_grade_at_delivery` STRING COMMENT 'Official grain quality grade assigned by the receiving elevator or inspection point at the time of delivery. May differ from the quality grade recorded at harvest on the yield_record due to storage, blending, or re-grading. Belongs to the delivery relationship.',
    CONSTRAINT pk_grain_delivery PRIMARY KEY(`grain_delivery_id`)
) COMMENT 'This association product represents the Grain Delivery event between a yield_record and a delivery_location. It captures the operational record of a specific quantity of harvested grain being allocated and physically delivered from a harvest operation to an authorized customer receiving location. Each record links one yield_record to one delivery_location and carries delivery-specific attributes — quantity, date, load ticket, quality grade at delivery, moisture at delivery, and COOL compliance — that exist only in the context of this specific delivery transaction and cannot reside on either the yield record or the delivery location alone.. Existence Justification: In grain merchandising operations, a single harvest load (yield_record) is routinely split across multiple delivery destinations — a grain elevator, an export terminal, and a food plant dock may all receive portions of the same harvest. Conversely, a customer delivery location receives commodity from many yield records across multiple fields, operators, and seasons. The business actively manages these allocations as grain deliveries or load allocations, tracking quantity delivered, moisture at delivery, quality grade, load ticket number, and COOL (Country of Origin Labeling) verification — data that belongs to neither the yield record nor the delivery location alone.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`prescription_zone_rate` (
    `prescription_zone_rate_id` BIGINT COMMENT 'Primary key for the prescription_zone_rate association',
    `input_product_id` BIGINT COMMENT 'Foreign key linking to the agricultural input product whose application rate is specified for this zone',
    `vra_prescription_id` BIGINT COMMENT 'Foreign key linking to the VRA prescription that contains this zone-level input rate specification',
    `application_method` STRING COMMENT 'The specific application method for this input product in this zone within the prescription (e.g., broadcast, banded, foliar). May differ per input within a multi-input prescription.',
    `prescribed_rate` DECIMAL(18,2) COMMENT 'The specific application rate prescribed for this input product in this management zone. Varies by zone and input combination; cannot reside on vra_prescription (varies per input) or input_product (varies per prescription and zone).',
    `rate_unit` STRING COMMENT 'Unit of measure for the prescribed_rate in this zone-input combination (e.g., lbs/ac, oz/ac, gal/ac). May differ across input products within the same prescription.',
    `zone_area_acres` DECIMAL(18,2) COMMENT 'The area in acres of the management zone covered by this input-prescription combination. Used to calculate total input quantity required for this zone and for cost/compliance reporting.',
    CONSTRAINT pk_prescription_zone_rate PRIMARY KEY(`prescription_zone_rate_id`)
) COMMENT 'This association product represents the zone-level input rate specification between a vra_prescription and an input_product. It captures the operational precision agriculture record that defines exactly how much of a specific input product is prescribed for a specific management zone within a VRA prescription. Each record links one vra_prescription to one input_product for one management zone, carrying the prescribed rate, area, and application method that exist only in the context of this zone-input-prescription combination. Sourced from Trimble Ag Software and Climate FieldView prescription workflows.. Existence Justification: A VRA prescription is specifically designed to apply multiple input products (e.g., N, P, K fertilizers simultaneously) at spatially variable rates across management zones, and each input product appears in many prescriptions across fields, seasons, and farms. The business actively manages this relationship as a prescription line item or zone-rate specification — a recognized operational concept in precision agriculture that carries zone-specific rate, area, and method data. This is not an analytical correlation; agronomists and equipment controllers actively create, update, and execute these zone-rate records as part of the VRA workflow.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`crop` (
    `crop_id` BIGINT COMMENT 'Primary key for crop',
    `parent_crop_id` BIGINT COMMENT 'Self-referencing FK on crop (parent_crop_id)',
    `average_yield` DECIMAL(18,2) COMMENT 'Historical average yield for this crop expressed in the yield_unit, used for crop planning and forecasting.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this crop master record was first created in the system.',
    `crop_category` STRING COMMENT 'High-level classification of the crop type based on agricultural use and market segment.',
    `crop_code` STRING COMMENT 'Standardized alphanumeric code used for crop identification in Farm Management Information Systems (FMIS) and regulatory reporting. Externally-known unique identifier.',
    `crop_name` STRING COMMENT 'Common name of the crop (e.g., Corn, Wheat, Soybeans, Cotton). Human-readable identifier used across all agronomic systems.',
    `crop_type` STRING COMMENT 'Classification based on the crops lifecycle duration: annual (single season), perennial (multi-year), or biennial (two-year cycle).',
    `disease_susceptibility` STRING COMMENT 'General susceptibility of the crop to disease infections, used in IPM-based disease management strategies.',
    `drought_tolerance` STRING COMMENT 'Crops ability to withstand water stress and drought conditions, critical for irrigation planning.',
    `frost_tolerance` STRING COMMENT 'Crops ability to withstand frost conditions during growing season.',
    `gmo_available` BOOLEAN COMMENT 'Indicates whether genetically modified varieties of this crop are available and approved for cultivation.',
    `growing_season` STRING COMMENT 'Primary season during which the crop is typically cultivated, used for crop planning and rotation scheduling.',
    `harvest_method` STRING COMMENT 'Primary method used for harvesting the crop: manual labor, mechanical equipment, or combination.',
    `market_price_per_unit` DECIMAL(18,2) COMMENT 'Current market price per yield unit (e.g., price per bushel, price per kilogram), used for revenue forecasting and crop selection decisions.',
    `maturity_days_max` STRING COMMENT 'Maximum number of days from planting to harvest maturity for late-maturing varieties of this crop.',
    `maturity_days_min` STRING COMMENT 'Minimum number of days from planting to harvest maturity for early-maturing varieties of this crop.',
    `ndvi_threshold_healthy` DECIMAL(18,2) COMMENT 'Normalized Difference Vegetation Index (NDVI) threshold value indicating healthy crop vigor, used for remote sensing and field health monitoring.',
    `nitrogen_requirement_kg_per_hectare` DECIMAL(18,2) COMMENT 'Recommended nitrogen fertilizer application rate in kilograms per hectare for optimal yield, used in Variable Rate Application (VRA) prescriptions.',
    `notes` STRING COMMENT 'Free-text field for additional agronomic notes, special cultivation requirements, or regional considerations for this crop.',
    `organic_certified` BOOLEAN COMMENT 'Indicates whether this crop can be grown under organic certification standards.',
    `pest_susceptibility` STRING COMMENT 'General susceptibility of the crop to pest infestations, used in Integrated Pest Management (IPM) planning.',
    `phi_days` STRING COMMENT 'Pre-Harvest Interval (PHI) - minimum number of days required between last pesticide application and harvest to ensure compliance with food safety regulations.',
    `phosphorus_requirement_kg_per_hectare` DECIMAL(18,2) COMMENT 'Recommended phosphorus fertilizer application rate in kilograms per hectare for optimal yield.',
    `planting_depth_cm` DECIMAL(18,2) COMMENT 'Recommended seed planting depth in centimeters for optimal germination and establishment.',
    `potassium_requirement_kg_per_hectare` DECIMAL(18,2) COMMENT 'Recommended potassium fertilizer application rate in kilograms per hectare for optimal yield.',
    `rei_hours` STRING COMMENT 'Restricted Entry Interval (REI) - minimum number of hours workers must wait before entering treated fields after pesticide application, ensuring worker safety compliance.',
    `rotation_compatible` BOOLEAN COMMENT 'Indicates whether this crop is suitable for inclusion in crop rotation schedules to maintain soil health and reduce pest pressure.',
    `row_spacing_cm` DECIMAL(18,2) COMMENT 'Recommended distance between crop rows in centimeters for optimal growth and equipment access.',
    `scientific_name` STRING COMMENT 'Scientific botanical name of the crop using binomial nomenclature (e.g., Zea mays for corn, Triticum aestivum for wheat).',
    `seeding_rate_kg_per_hectare` DECIMAL(18,2) COMMENT 'Recommended seeding rate in kilograms per hectare for standard planting density.',
    `soil_ph_max` DECIMAL(18,2) COMMENT 'Maximum soil pH level tolerated by the crop for healthy growth.',
    `soil_ph_min` DECIMAL(18,2) COMMENT 'Minimum soil pH level required for optimal crop growth and nutrient availability.',
    `crop_status` STRING COMMENT 'Current lifecycle status of the crop in the master reference system. Active crops are available for planting schedules and field assignments.',
    `temperature_max_celsius` DECIMAL(18,2) COMMENT 'Maximum temperature in Celsius tolerated by the crop before heat stress occurs.',
    `temperature_min_celsius` DECIMAL(18,2) COMMENT 'Minimum temperature in Celsius required for crop germination and growth.',
    `updated_timestamp` TIMESTAMP COMMENT 'Timestamp when this crop master record was last modified.',
    `water_requirement_mm` DECIMAL(18,2) COMMENT 'Total seasonal water requirement in millimeters, used for Evapotranspiration (ET)-driven irrigation planning.',
    `yield_unit` STRING COMMENT 'Standard unit of measure for crop yield reporting (e.g., bushels per acre for corn, kilograms per hectare for wheat). Used in Yield Per Minute (YPM) calculations.',
    CONSTRAINT pk_crop PRIMARY KEY(`crop_id`)
) COMMENT 'Master reference table for crop. Referenced by crop_id.';

CREATE OR REPLACE TABLE `agriculture_ecm`.`crop`.`zone_map` (
    `zone_map_id` BIGINT COMMENT 'Primary key for zone_map',
    `growing_season_id` BIGINT COMMENT 'Reference to the specific crop season or growing period for which this zone map is applicable. Links the map to temporal crop planning cycles.',
    `farm_unit_id` BIGINT COMMENT 'Reference to the farm or agricultural operation that owns or manages the field associated with this zone map.',
    `field_id` BIGINT COMMENT 'Reference to the agricultural field for which this zone map was created. Links the zone map to the specific field boundary and location.',
    `parent_zone_map_id` BIGINT COMMENT 'Self-referencing FK on zone_map (parent_zone_map_id)',
    `approval_date` DATE COMMENT 'Date when the zone map was formally approved for use in field operations and variable rate application prescriptions.',
    `approved_by` STRING COMMENT 'Username or identifier of the supervisor, agronomist, or authorized personnel who reviewed and approved the zone map for operational use.',
    `attribute_measured` STRING COMMENT 'Specific agronomic or environmental attribute measured or represented in the zone map (e.g., soil pH, organic matter percentage, elevation above sea level, NDVI value, soil moisture content).',
    `classification_method` STRING COMMENT 'Algorithm or methodology used to classify and delineate management zones within the map (e.g., manual delineation, k-means clustering, supervised classification, unsupervised classification, threshold-based).',
    `collection_date` DATE COMMENT 'Date when the underlying data for the zone map was collected or captured. Important for understanding temporal relevance and data currency.',
    `coordinate_system` STRING COMMENT 'Spatial reference system or coordinate system used for the zone map (e.g., EPSG:4326 for WGS84, EPSG:32633 for UTM Zone 33N). Critical for accurate geospatial alignment.',
    `created_timestamp` TIMESTAMP COMMENT 'Timestamp when this zone map record was first created in the system. Audit field for data lineage and compliance tracking.',
    `data_source` STRING COMMENT 'Primary source of data used to generate the zone map, such as satellite imagery, drone-based remote sensing, in-field sensors, manual survey, yield monitor data, or soil sampling results.',
    `effective_from_date` DATE COMMENT 'Date from which this zone map becomes valid and applicable for field operations and variable rate application prescriptions.',
    `effective_until_date` DATE COMMENT 'Date until which this zone map remains valid. Nullable for maps with indefinite validity. Used for version control and temporal management.',
    `external_reference_code` STRING COMMENT 'Unique identifier or reference code for the zone map in the external source system. Enables cross-system traceability and data reconciliation.',
    `file_format` STRING COMMENT 'Digital file format in which the zone map is stored or distributed (e.g., Shapefile, GeoTIFF, GeoJSON, KML, ISO 11783 XML). Critical for system interoperability.',
    `file_path` STRING COMMENT 'Storage location or file path where the zone map digital file is stored within the data lake or file system. Used for retrieval and access management.',
    `file_size_mb` DECIMAL(18,2) COMMENT 'Size of the zone map file expressed in megabytes. Useful for storage management and data transfer planning.',
    `generation_date` DATE COMMENT 'Date when the zone map was generated or created from the source data. Distinct from collection date as processing may occur later.',
    `integration_system` STRING COMMENT 'Name of the external Farm Management Information System (FMIS) or precision agriculture platform from which the zone map was imported or to which it is exported (e.g., Climate FieldView, Trimble Ag Software, John Deere Operations Center).',
    `is_vra_enabled` BOOLEAN COMMENT 'Boolean flag indicating whether this zone map is actively used for variable rate application prescriptions in field operations (True) or is for reference only (False).',
    `map_code` STRING COMMENT 'Unique alphanumeric business identifier or code for the zone map, used for external reference and system integration.',
    `map_name` STRING COMMENT 'Human-readable name or title assigned to this zone map for identification and reference purposes.',
    `map_type` STRING COMMENT 'Classification of the zone map based on the agronomic or environmental attribute it represents (e.g., soil type, yield potential, elevation, NDVI vegetation index, soil moisture, nutrient levels).',
    `max_value` DECIMAL(18,2) COMMENT 'Maximum value of the measured attribute observed across all zones in the map. Defines the upper bound of the data range.',
    `mean_value` DECIMAL(18,2) COMMENT 'Average or mean value of the measured attribute across all zones in the map. Provides a central tendency measure for the field.',
    `min_value` DECIMAL(18,2) COMMENT 'Minimum value of the measured attribute observed across all zones in the map. Defines the lower bound of the data range.',
    `modified_timestamp` TIMESTAMP COMMENT 'Timestamp when this zone map record was last modified or updated. Audit field for change tracking and data governance.',
    `notes` STRING COMMENT 'Free-text field for additional notes, observations, or contextual information about the zone map, such as data quality issues, field conditions during collection, or special considerations.',
    `resolution_meters` DECIMAL(18,2) COMMENT 'Spatial resolution of the zone map expressed in meters, representing the grid cell size or minimum distinguishable feature size in the map.',
    `zone_map_status` STRING COMMENT 'Current lifecycle status of the zone map indicating whether it is in draft, actively used for field operations, archived for historical reference, superseded by a newer version, or deprecated.',
    `total_area_hectares` DECIMAL(18,2) COMMENT 'Total area covered by the zone map expressed in hectares. Represents the spatial extent of the mapped field or region.',
    `unit_of_measure` STRING COMMENT 'Unit of measurement for the attribute represented in the zone map (e.g., pH units, percent, meters, index value, volumetric water content).',
    `version_number` STRING COMMENT 'Version identifier for the zone map following semantic versioning (e.g., 1.0, 2.1). Enables tracking of map revisions and updates over time.',
    `zone_count` STRING COMMENT 'Total number of distinct management zones defined within this zone map. Indicates the granularity of the variable rate application (VRA) prescription.',
    `created_by` STRING COMMENT 'Username or identifier of the agronomist, precision agriculture specialist, or system user who created or generated the zone map.',
    CONSTRAINT pk_zone_map PRIMARY KEY(`zone_map_id`)
) COMMENT 'Master reference table for zone_map. Referenced by zone_map_id.';

